// 7. sınıf Türkçe soru bankasından paragraf soruları.
window.PARAGRAPH7_TURKCE_QUESTIONS = [{"grade":7,"topic":"Konu bulma","difficulty":"Orta","outcome":"Konu bulma","text":"Böyle uzaklaşmayın benden, yaşadığım günler\nGüneş! Getir bir bayram sabahını\nAçılın, açılın tekrar\nÇocuk dizlerimdeki yaralar","stem":"Aşağıdakilerden hangisi konu bakımından bu şiirle ilişkilendirilebilir?","options":["Kızınca üzülecek\nKırılıp incinecek\nSevilince gülecek\nÇocuk nazlı bir çiçek","Çocukluğum, çocukluğum\nBir çekmecede unutulmuş\nSenelerle rengi solmuş\nBir tek resim çocukluğum","Yoksul bir çocuk görsem\nYağmur altında üşüyen\nKöprü olmak geçer\nHiç değilse içimden","Kim bilir şimdi neredesin\nSenindir yeni akşamlar\nMerdivende ayak sesin\nRıhtım taşında gölgen var"],"answer":"B","solution":"Doğru cevap B seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"","stem":"Aşağıdaki parçalardan hangisi “İnsanlar yaşlanınca\nneden yüzleri kırışır?” sorusuna cevap vermektedir?","options":["Mimik kasları, duygu ve düşünceleri yansıtmaya yardımcı olan yüz kaslarıdır. Ancak bazı mimik\nkaslarını gereğinden fazla kullanmak yüzümüzde\nistenmeyen çizgilerin oluşmasına yol açar. Özellikle\nalın, kaş ortasında ve göz kenarlarında kırışıklıklar\nve çizgiler oluşur.","Cilt sağlığımızı etkileyen kırışıklıkları engellemeye\nyardımcı olmak için öncelikle beslenmemize dikkat\netmeliyiz. Ayrıca stresten ve kötü alışkanlıklardan\nuzak durmalı ve günde en az 2 litre su tüketmeye\nözen göstermeliyiz.","Kırışıklık, yaşlanmanın cilt üzerindeki doğal sonuçlarından biridir. Kırışıklıklar; ciltte en çok yüz,\nboyun, eller ve ön kollar gibi güneşe maruz kalan\nbölgelerde belirgindir. Cilt yapısı ve dokusu genetiğe bağlı olsa da açık tenli kişiler için kırışıklıkların\nbaşlıca nedeni güneşe maruz kalmadır.","İnsan derisi üç tabakadan oluşur. Derinin esnekliğini ve sıkılığını deri altı tabakada bulunan elastin\nve kolajen adlı proteinler sağlar. Yaş ilerledikçe derideki elastin ve kolajen miktarı azalır. Zamanla deri\naltındaki yağ oranının da azalmasıyla üst deri eski\nsıkılığını kaybederek gevşemeye başlar."],"answer":"D","solution":"Doğru cevap D seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Konu bulma","difficulty":"Orta","outcome":"Konu bulma","text":"Paragrafın konusunu en açık ve en net biçimde yansıtan kelime veya kelime gruplarına “anahtar kelime”\ndenir.","stem":"Aşağıdaki metinlerden hangisi “karınca, yuva, iletişim, koku” anahtar kelimelerinden hareketle\noluşturulmuştur?","options":["Karıncalar, başlarının üzerindeki antenlerle iletişim\nkurar. Bir karınca büyük bir besin bulduğunda diğer\nkarıncalara haber vermek için yuvaya giderken özel\nbir koku bırakır. Diğer karıncalar bu kokuyu takip\nederek besinin olduğu yere gider ve besini yuvalarına taşır. Tünele benzeyen bu yuvaların derinliği 4\nmetreyi bulabilir.","Karıncalar, yuvalarından çıkmak için bütün bir kış\nboyunca ilkbaharın gelmesini ve karların erimesini\nbekler. Bu sürede yuvalarında kış uykusuna yatar.\nBahçede, parkta, ormanda kısacası birçok yerde\ngördüğümüz karıncaların yuvaları farklı odacıklardan oluşan yer altı tünellerine benzer.","Karınca yuvalarında bulunan her bir odanın ayrı bir\nişlevi vardır. Bazı odalarda yavrular bulunurken bazılarında besinler depolanır. Her yuvada bir kraliçe\nkarınca ile erkek ve işçi karıncalar vardır. İşçi karıncalar yuvanın en çalışkanlarıdır. Yuvaları genellikle\nonlar yapar. Enerjilerini ise tatlı besinlerden alır.","Vücutları baş, göğüs ve gövdeden oluşan karıncalar, başlarının üzerindeki antenleri birbirine\ndeğdirerek diğer karıncanın hangi yuvada yaşadığı hakkında bilgi edinir. Aynı yuvaya ait karıncalar\nbu özel yöntem sayesinde iletişim kurarak aynı\nyuvadaki karıncaları tanır ve birlikte yuvaya gerekli\nbesini taşır."],"answer":"A","solution":"Doğru cevap A seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Başlık bulma","difficulty":"Orta","outcome":"Başlık bulma","text":"Araştırmacılar pencerelerdeki cam katmanlarının\nardından su geçirebilen yeni bir pencere teknolojisi\ngeliştirdi. Geleneksel üç camlı pencere sistemlerindeki cam tabakalar arasında ısı yalıtımı sağlamak\namacıyla argon gazı kullanılıyor. Araştırmacılar\nbunun yerine güneş ışığından ısı soğurma yeteneği dolayısıyla su kullanmayı denediler. Bunun\niçin tabakaları arasına yavaş bir şekilde su pompalanan pencere sistemleriyle iki küçük prototip\nbina oluşturuldu. Katmanlar arasındaki su, güneş\nışınlarıyla ısınınca sıcak su üretmek ya da mekân\nısıtmak amacıyla kullanılarak enerji tasarrufu sağlıyor. Su akışının, pencerenin şeffaflığını ve sağladığı\ngörüntüyü bozmayacak ölçüde yavaş olduğunu\nbelirtiyor. Araştırmacılar, bu sistemin soğuk iklim\nhariç her yerde geleneksel pencere sistemlerine\nüstün geldiğini gördüler.","stem":"Bu metne getirilebilecek en uygun başlık aşağıdakilerden hangisidir?","options":["Kendi Kendini Temizleyen Pencereler","Su Tasarrufunun Yolları","Suyla Enerji Tasarrufu Sağlayan Pencereler","Geleneksel Pencere Sistemlerinin Zararları"],"answer":"C","solution":"Doğru cevap C seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"Gazeteci: (I) - - - -\nÜnlü modacı: Hayır, yabancı bir ismin varsa hırpalanabiliyorsun ama babam “Roma’daysan Romalılar\ngibi davranman gerekiyor!” derdi hep. Ben de öyle\nyaptım. İngiltere’ye uyum sağladım.\nGazeteci: (II) - - - -\nÜnlü modacı: Aslında ailem mimar olmamı istiyordu.\nAma bana modada farklı bir şey yapabilme fikri cazip\ngeldi. Sanatçı olsaydım belki de yeni bir şey yapamazdım ama bu yolla yaptım. Modadaki boşluğu keşfettim\nve bu alana damgamı vurdum.","stem":"Bu konuşmada boş bırakılan yerlere sırasıyla aşağıdakilerden hangileri getirilmelidir?","options":["(I) Hiç bocalamadınız mı İngiltere’de?\n(II) Moda sektörünü tercih etmenizin özel bir sebebi\nvar mı?","(I) İngiltere’ye alışmakta zorlandınız mı?\n(II) Çocukken en çok ne olmak isterdiniz?","(I) Adınızın Türkçe olması İngiltere’de sizi zora soktu mu?\n(II) Modacı olma fikrini size kim aşıladı?","(I) İngiltere’de ilk defa mı bulunuyorsunuz?\n(II) Niçin başka meslekleri değil de modacılığı seçtiniz?"],"answer":"A","solution":"Doğru cevap A seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"İstanbul Hukuk Fakültesinde bir Alman profesör varmış. 10 Kasım günü yürekleri burkan acı haberi o da duymuş. Derse\ngirip girmeme konusunda kararsızlık yaşamış. Rektörün yanına gittiğinde aralarında şu konuşma geçmiş:\n— Efendim, kararsızım. Acaba ne yapsam?\n— Sizde böyle büyük adam ölünce ne yaparlarsa onu yapın.\n— Bizde bu kadar büyük bir adam ölmedi ki...","stem":"Bu metinde Alman profesörün hangi yönü vurgulanmıştır?","options":["Atatürk’e olan derin saygısı","Kendi milletini sevmemesi","Derslerine önem vermesi","Türkiye’de çalışması"],"answer":"A","solution":"Doğru cevap A seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Konu bulma","difficulty":"Orta","outcome":"Konu bulma","text":"Televizyonun evlere ilk girdiği dönemlerde çocukların\nekran karşısında geçirdiği süre, genelde sabah erken\nsaatlerde ve hafta sonları yayımlanan çizgi film saatleriyle sınırlıydı. Çocuklar vakitlerinin çoğunu ev dışında\narkadaşlarıyla oynayarak geçirirdi. Sabah akşam çizgi\nfilm yayını yapan kanalların açılması ve bilgisayar, akıllı\ntelefon, tablet vb. cihazların ortaya çıkmasıyla ebeveynler, günün büyük kısmını bunların karşısında geçiren\nçocukları ekrandan koparamaz oldu.","stem":"Bu metnin konusu aşağıdakilerden hangisidir?","options":["Teknolojik cihazlardaki hızlı değişim","Teknolojinin çocuk eğitimine katkısı","Teknolojiyle değişen çocukluk","Teknolojinin aile kurumuna etkisi"],"answer":"C","solution":"Doğru cevap C seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Başlık bulma","difficulty":"Orta","outcome":"Başlık bulma","text":"İlk örneklerine 14 ve 15. yüzyıllarda Bursa ve Edirne’de rastladığımız eski kitap alıp satma mesleği olan\nsahaflık, matbaanın bulunmadığı bir toplumda medrese öğrencilerinin kitap ihtiyacını karşılamak için tesis\nedilmiş bir ticari faaliyet olarak gelişmiştir. Sahaflık,\nSemâniye Medreselerinin kurulmasıyla İstanbul’a kaymıştır. Bugün bir dernekle temsil edilen sahaflık, eski\ncanlılığını ve ilgi çekiciliğini yitirmekle beraber farklı\nmerkezlerde varlığını sürdürmeye çalışıyor.","stem":"Bu metne getirilebilecek en uygun başlık aşağıdakilerden hangisidir?","options":["Günümüzde Sahaflık","Osmanlıda Kitapçılık","Medrese ve Kitap","Dünden Bugüne Sahaflık"],"answer":"D","solution":"Doğru cevap D seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"Bitkiler kökleriyle topraktan aldıkları suyu, besin üretiminde kullanmak üzere gövdeden yapraklarına iletir. Suyun önemli\nbir kısmı yaprakların içinde buharlaşır. Sonra da yapraklarda bulunan ve bitkideki terlemeyi de kontrol eden gözeneklere gönderilir. Buharlaşan suyun büyük çoğunluğu, tıpkı bizim derimizden çıkan ter gibi bitkinin bu gözeneklerinden\ndışarı çıkar. Böylece bitki terleyerek serinler.","stem":"Aşağıdakilerden hangisi bu metnin anahtar sözcüklerinden biri değildir?","options":["Bitki","Deri","Terleme","Buharlaşma"],"answer":"B","solution":"Doğru cevap B seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Konu bulma","difficulty":"Orta","outcome":"Konu bulma","text":"Televizyona düşkün çocuklar, ailesiyle, arkadaşlarıyla ve diğer insanlarla sosyal ilişki kurmada isteksiz davranır. Bu\nçocuklar, kitap okumak ve ders çalışmak gibi zihinsel çaba gerektiren işlerden hoşlanmaz. Televizyon karşısında daima\nalıcı durumda oldukları için konuşmaya ihtiyaç duymaz, çocukların dil becerileri gelişmez.","stem":"Bu metnin konusu aşağıdakilerden hangisidir?","options":["Televizyon bağımlılığının çocuklar üzerindeki olumsuz etkileri","Televizyon izleyen çocukların hayal gücünün yok olması","Televizyona bağlı çocukların okumaktan hoşlanmaması","Televizyon tutkusunun çocuklarda sosyal becerileri zayıflatması"],"answer":"A","solution":"Doğru cevap A seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"Yirmi yıl bu sektöre kamera arkasında hizmet ettikten\nsonra asıl durmak istediğim yerin kameranın önü olduğunu anladım. Zihnimdeki karakterlere hayat veren\nneden ben olmayayım, dedim. Hem başarısız kabul\nedilen filmlerin günah keçisi hep yönetmen değil midir? Ne yalan söyleyeyim, kamera arkasında isimsiz\nkahraman olmaktansa ışıklar altında alkışlanma düşüncesi de hoşuma gitmedi değil.","stem":"Bu parça aşağıdaki sorulardan hangisine karşılık\nsöylenmiş olabilir?","options":["Bir oyuncunun yönetmenlik deneyimi olmasının\navantajları nelerdir?","Sinema sektöründe yönetmenlerin karşılaştığı zorluklar nelerdir?","Yönetmenlikten oyunculuğa geçmeye nasıl karar\nverdiniz?","Eski yönetmen, yeni oyuncu olarak hedefleriniz nelerdir?"],"answer":"C","solution":"Doğru cevap C seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Yardımcı düşünce","difficulty":"Orta","outcome":"Yardımcı düşünce","text":"","stem":"Dünya nasıl nefes alıyor, hiç merak ettiniz mi? Tabii ki\normanlar sayesinde! Ormanlar dünyanın en önemli oksijen kaynaklarındandır. Sadece bulundukları bölgenin\nhavasını temizlemez, bölgenin bol yağış almasını da\nsağlar. Atmosferdeki gazların dengesinin korunmasında önemli etkileri vardır ve iklim üzerinde düzenleyici\netkiye sahiptir. Ayrıca ormanlardaki ağaçların kökleri\ntoprağı tutarak erozyon, sel gibi doğal afetleri önler.\nBu parçayla ilgili aşağıdakilerden hangisi söylenemez?","options":["Metnin başlığı “Dünyaya Can Veren Ormanlar” olarak belirlenebilir.","Metnin konusu “Ormanların dünyamız için önemi”-\ndir.","“Orman, iklim, doğal afet” metnin anahtar kelimelerindendir.","“Ormanları koruma yolları nelerdir?” sorusunun cevabı niteliğindedir."],"answer":"D","solution":"Doğru cevap D seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Ana düşünce","difficulty":"Orta","outcome":"Ana düşünce","text":"Hocamız sınav kâğıtlarını dağıttı. Son soruya kadar\nsoluk almadan geldim ama orada çakıldım kaldım.\nSon soru, iletişim sorusuydu. Tam 50 puan! Soru şöyleydi: “Her gün okulumuzu temizleyen görevlinin adı\nnedir?” Bu bir şaka olmalıydı. Kadını, yerleri silerken\nhemen her gün görüyordum. Uzun boylu, siyah saçlı bir kadındı. 50’lerinde olmalıydı. Ama adını nereden\nbilecektim ki! Son soruyu yanıtsız bırakıp kâğıdı teslim\nettim. Öğretmenimizin bu soruyla bize verdiği dersi\nhayatım boyunca unutmadım. O görevlinin adını da…","stem":"Bu metinde asıl anlatılmak istenen aşağıdakilerden hangisidir?","options":["Günlük yaşam içinde sıklıkla karşılaştığınız insanların özel hayatını bilmelisiniz.","Yaşamınız boyunca karşılaşacağınız tüm insanlar\nilginizi ve dikkatinizi hak eder.","Size hizmet eden kim olursa olsun, zaman zaman\nona hâl hatır sormalısınız.","Sınavlara hazırlanırken sadece ders çalışmamalı,\nhayata da hazırlanmalısınız."],"answer":"B","solution":"Doğru cevap B seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"Pençesi dibinde bir aslanın\nDalgınlıkla bir fare çıkıverdi\nBu fırsatı kullanmadı sultanı ormanın\nFareye dokunmayıp bir büyüklük gösterdi\nBu iyiliği boşa gitti sanmayın\nKimin aklına gelir ki bir an fareye işi düşer aslanın\nAma o da bir gün dışarı çıktı ormandan\nGitti tutuldu bir ağa\nNe çırpınma ne kükreme… Kâr etmez tuzağa\nBay fare koştu, dişiyle aslanın ağını\nÖyle bir kemirdi ki ağ söküldü nihayet\nKurtarmıştı farecik ormanlar kralı aslanı","stem":"Aşağıdaki atasözlerinden hangisi bu metinle aynı\niletiye sahiptir?","options":["İyiliğe iyilik her kişinin kârı, kötülüğe iyilik er kişinin\nkârı.","İyilik eden iyilik bulur.","İyilik et denize at, balık bilmezse Halik bilir.","İyilik iki baştan olur."],"answer":"B","solution":"Doğru cevap B seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"I. Dil değerlendirir insanı, onunla mutluluğa erer\nDil değerden düşürür insanı, dili yüzünden başı gider\nII. Kalp deniz, dil kıyıdır\nDenizde ne varsa kıyıya o vurur\nIII. Bu şakıyan ses beni titretir yüreğimden\nBülbül sesi değil o, benim güzel Türkçemdir","stem":"Numaralanmış dizelerden hangileri,\nÇinli filozof Konfüçyüs’e sorarlar: “Bir ülkeyi idare\netmeye çağrılsaydınız yapacağınız ilk iş ne olurdu?”\nKonfüçyüs şöyle der: “İşe önce dili düzeltmekle başlardım. Çünkü dil bozulursa kelimeler düşünceleri\nanlatamaz. Düşünceler iyi anlatılmazsa yapılması gereken işler yapılmaz. İşler gereği gibi yapılmazsa töre\nve düzen bozulur. Töre ve düzen bozulursa adalet yoldan sapar. Adalet yoldan çıkarsa şaşkınlık içine düşen\nhalk ne yapacağını, işin nereye varacağını bilemez.\nBunun içindir ki hiçbir şey dil kadar önemli değildir.”\nmetninin ana fikriyle aynı iletiye sahiptir?","options":["Yalnız I","I ve III","II ve III","I, II ve III"],"answer":"A","solution":"Doğru cevap A seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"Karlar içinde yattın, yılmadın\nYurttan düşmanı attın, durmadın\nAtam yokluk içinde bile sen\nYeni devlet, hür bir millet yarattın","stem":"Bu metinden Atatürk’ün aşağıdaki kişilik özelliklerinden hangisi vurgulanmamıştır?","options":["Kararlılığı","Kahramanlığı","Açık sözlülüğü","Liderliği"],"answer":"C","solution":"Doğru cevap C seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"Hani o bırakıp giderken seni\nBu öksüz tavrını takmayacaktın\nAlnına koyarken veda buseni\nYüzüme bu türlü bakmayacaktın","stem":"Bu şiirin teması aşağıdakilerden hangisidir?","options":["Ayrılık","Doğa sevgisi","Ümitsizlik","Dostluk"],"answer":"A","solution":"Doğru cevap A seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"Roman yazmak, olaylara bir balkondan bakmanın\nzevkini taşır.","stem":"Aşağıdaki metinlerden hangisinin vermiş olduğu\nileti bu cümleyle ilişkilendirilebilir?","options":["Elma deyip geçmeyin, elinize tek bir elma ya da\nherhangi bir nesne alarak bile birçok yeni buluş\nortaya çıkarabilirsiniz. Bu hem bu kadar basit hem\nde zor ve karışık. Ama bu karmaşadan korkmayın.\nElmayı buluşa çevirecek güce sahip olduğunuza\ninanın.","Bir olayın patron ve işçi açısından anlamı farklı\nolabilir; zengin ile fakir, öğretmen ile öğrenci, anne\nbaba ile çocuk olaylara farklı pencerelerden bakarlar. Bu anlamda olaylara farklı bakmamızda sosyal\nstatünün önemli bir etken olduğunu görürüz.","Bir bebek, yılan hakkında herhangi bir yargısı yokken ailesinin tepkilerini izler ve yılandan korkması\ngerektiğini öğrenir. İnsan, yaşamı boyunca nelerden\nkorkması gerektiği, nelerin iyi, nelerin kötü olduğu\nkonusunda çevre tarafından ön yargılar ile doldurulur.","Bir labirentin içinde olsanız çıkışı ya da labirentteki\nyolları görebilir misiniz? Elbette hayır. Ama yukarıda olsanız hem labirenti hem de çıkışı görebilirsiniz.\nGeri çekilmek, daima net bir görüş sağlar. O zaman\ndoğru seçimleri yapmak ve olayı ışığa kavuşturmak\nmümkündür."],"answer":"D","solution":"Doğru cevap D seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Ana düşünce","difficulty":"Orta","outcome":"Ana düşünce","text":"Nasrettin Hoca’nın komşusu olan bir sütçü varmış.\nSütü, içine su katarak satarmış. Kimse de bunu fark\netmezmiş. Nasrettin Hoca ona ne kadar nasihat verirse versin, o bildiğinden şaşmazmış. Bir gün büyük\nbir sel olmuş. Sütçünün bütün inekleri, koyunları sele\nkapılıp gitmiş. Sütçü bu duruma çok üzülmüş. Dövünüp durmuş. Nasrettin Hoca, komşusunun durumunu\ngörünce ona ne olduğunu sormuş. Sütçü “Bütün hayvanlarımı sel götürdü.” deyince Hoca ona şöyle demiş:\n“- - - -”","stem":"Bu metindeki boşluğa aşağıdakilerden hangisi getirilirse Nasrettin Hoca metnin ana düşüncesini\ndestekleyen bir söz söylemiş olur?","options":["Su ile gelen, sonunda böyle su ile gider.","Başkalarının ahını alan sonunda ah vah eder.","Büyüğünü dinlemeyen, büyük derde düşer.","Talih her zaman yüzüne gülmez, biraz da çaba göster."],"answer":"A","solution":"Doğru cevap A seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"","stem":"Ben çocuklarıma hep şunu öğütlerim: “Koşullar ne\nolursa olsun insanlara verdiğiniz sözleri yerine getirin. Tutamayacağınız sözler vermeyin. İnsanları hayal\nkırıklığına uğratmayın ve onlara asla yalan söylemeyin. Açığa çıkmış her yalan, insanlarla aranızdaki cam\nköprülere fırlatılan taşlardır. Size verilen sırrı kimseye\naçmayın, emanete hıyanet etmeyin.”\nÖğütlerinden böyle söz eden bir kişinin çocuklarına\nöncelikle aşılamak istediği duygu aşağıdakilerden\nhangisidir?","options":["Dostluk","İyilik","Sabır","Güven"],"answer":"D","solution":"Doğru cevap D seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Ana duygu","difficulty":"Orta","outcome":"Ana duygu","text":"","stem":"Beton duvarlar arasında bir çiçek açtı\nSiz kahramanısınız çelik dişliler arasında direnen insanlığın\nSaçlarınız ızdırap denizinde bir tutam başak\nElleriniz kök salmış ağacıdır zamana\nO inanmışlar çağının\nBu dizelerde hâkim olan duygu aşağıdakilerin hangisidir?","options":["Umut","Şaşırma","Özlem","Sitem"],"answer":"A","solution":"Doğru cevap A seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Ana düşünce","difficulty":"Orta","outcome":"Ana düşünce","text":"Bir gün bir adam Sokrates’e “Arkadaşınla ilgili ne duyduğumu biliyor musun?” der. Sokrates “Bir dakika\nbekle.” diye cevap verir ve devam eder: “Bana arkadaşımla ilgili bir şey söylemeden evvel seni küçük bir\ntestten geçireyim. Öncelikle bana birazdan söyleyeceğin şeyin tam olarak gerçek olduğundan emin misin?”\nAdam “Hayır, aslında bunu sadece duydum.” der. “Peki!” der Sokrates ve sorar: “Arkadaşım hakkında bana\nsöylemek istediğin şey, iyi bir şey mi?” Adam “Hayır,\ntam tersi!” diye cevap verir. Sokrates “Peki, bana arkadaşım hakkında söyleyeceğin şey, benim için yararlı\nmı?” diye sorar. Adam “Hayır!” deyince Sokrates adamı susturur: “O hâlde söyleme!”","stem":"Bu metinde asıl anlatılmak istenen aşağıdakilerden hangisidir?","options":["Arkadaşların adının geçtiği dedikoduların gerçeklik\npayı iyice araştırılmalıdır.","Arkadaşlarla ilgili öğrenilen bazı gerçekler, ilişkilere\nzarar verebileceğinden dikkate alınmamalıdır.","Arkadaşlarla ilgili olumsuz, yararsız ve kulaktan\ndolma bilgilere kulak verilmemelidir.","Arkadaşlık ilişkilerine zarar verebilecek kötü, faydasız ve gerçek dışı haberler yayılmamalıdır."],"answer":"C","solution":"Doğru cevap C seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Ana düşünce","difficulty":"Orta","outcome":"Ana düşünce","text":"67 yaşındayken oğlunu kaybetmiş Tolstoy. Yas\ntutuyor, acısıyla başa çıkmaya çalışıyormuş. Aynı\ndönem, Moskova Bisiklet Sevenler Derneği, büyük\nyazara anı olarak bir bisiklet hediye etmiş. Evinin\nbahçesinde, eşi Sonya’nın endişeli bakışları altında, kendi kendine, düşe kalka bisiklete binmeyi\nöğrenmiş Tolstoy. 67 yaşında tanıştığı bisikletin\npedalına bastıkça geride bırakmış acısını. Ve kimse\nindirememiş ünlü yazarı artık bisikletinden.","stem":"Bu metnin ana düşüncesi aşağıdakilerden hangisidir?","options":["İleri yaşlarda edinilen alışkanlıklar, kolay bırakılamaz.","Hayatta hiçbir şey için geç değildir.","Hayatın tadı anı yaşayarak çıkarılır.","Bir işe başlamak, başarmanın yarısıdır."],"answer":"B","solution":"Doğru cevap B seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"Aldığım mektuplardan bazılarında şöyle şeyler yazılıdır: “Bir resim yaptım ama sonuçtan hiç memnun\nkalmadım!” Bu harika bir şeydir. Çünkü insanda bir\nsonraki resme başlama arzusu uyandırır. Yolunda gitmeyen şeyin ne olduğunu anlarsınız. Umarım yaşam\nboyu ara ara böyle duygulara kapılırsınız!","stem":"Bu metinde vurgulanan düşünce aşağıdakilerden\nhangisidir?","options":["Kendiyle barışık insan, eksiklerinin farkında olan insandır.","Öğrenmenin yaşı ve zamanı yoktur.","Öz eleştiri, insanın kendini geliştirip en iyiye ulaşmaya çalışmasını sağlar.","Başarı, yetenek ve çok çalışmanın birlikteliği ile elde edilebilir."],"answer":"C","solution":"Doğru cevap C seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"Günlük hayatta bizi ilgilendiren ya da ilgilendirmeyen\nonlarca olayla karşılaşır ve çeşitli duygulara kapılırız. Bizlerden çok daha hassas bir yapıya sahip olan\nsanatçıların gördükleri karşısında hissiz kalması mümkün müdür? Tabii ki hayır! Ancak sanatçıların garip\nbir huyu vardır. Onların kalemlerini oynatan, fırçalarını\nharekete geçiren, parmaklarını bir sazın tellerinde gezdiren şey; her zaman sevinçten çok keder olmuştur.\nOnlar hüzün denizinde yüzmeyi hatta boğulmayı nedense pek severler.","stem":"Bu metinde sanatçıların hangi yönü vurgulanmıştır?","options":["Toplumsal meselelere duyarlı olmaları","Olumsuz duygulardan yola çıkarak eserlerini oluşturmaları","Başkalarının felaketlerinden ve üzüntülerinden ilham almaları","Hassas yapıları gereği başkaları mutsuzken mutlu\nolmayı reddetmeleri"],"answer":"B","solution":"Doğru cevap B seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"Eğer sizden sokakları süpürmeniz istenirse Micheangelo’nun resim yaptığı, Beethoven’ın beste yaptığı\nveya Shakespeare’in şiir yazdığı gibi süpürün. O kadar güzel süpürün ki gökteki ve yerdeki herkes durup\n“Burada dünyanın en iyi çöpçüsü yaşıyormuş.” desin.","stem":"Bu metinde yazarın asıl anlatmak istediği aşağıdakilerden hangisidir?","options":["İnsan her yaptığıyla kendinden söz ettirmelidir.","Yaptığı işin en çok hakkını verenler, sanatçılardır.","Bir işte başarılı olmak için o işi gerçekten sevmek\ngerekir.","Her ne işi yapıyorsanız yapın, o işi en mükemmel\nşekliyle yapın."],"answer":"D","solution":"Doğru cevap D seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Ana duygu","difficulty":"Orta","outcome":"Ana duygu","text":"","stem":"Ah, o kadrini bilmediğim günler\nKoklamadan attığım gül demeti\nSuyunu sebil ettiğim o çeşme\nEserken yelken açmadığım rüzgâr\nGel gör ki sular batıya meyleder\nÇağınız başlıyor, ey hatıralar\nBu dizelere hâkim olan duygu aşağıdakilerden\nhangisidir?","options":["Pişmanlık","Yalnızlık","Korku","Umutsuzluk"],"answer":"A","solution":"Doğru cevap A seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"Çağımızın getirdiği en büyük teknoloji ve kolaylık olan internetin yaygın olması birtakım tehlikeleri beraberinde getirmiştir. Bu yüzden tedbirli olmakta yarar var. Tüm internet sağlayıcılarının zorunlu olarak sunmuş olduğu “güvenli internet”i\ntercih ederek hem kendiniz hem çocuklarınız için ilk adımı atabilirsiniz. Bununla birlikte internete girilecek cihazda\ngüvenilir bir antivirüs programı olması yerinde bir tedbir olacaktır. İnternet tarayıcıları, internet geçmişini kaydedebilir\nfakat geçmişi silmek de bir o kadar kolaydır. Öyleyse internetten soyutlanmak değil, bu konuda bilinçlenmek gerekir.","stem":"Aşağıdaki cümlelerden hangisi bu metinle benzer bir iletiye sahiptir?","options":["Kendinizi ve ailenizi internetten değil, internette koruyun.","Kendinizi ve çocuklarınızı korumak için internetten uzak durun.","İnternetin kişi için yararları kadar zararları da bulunmaktadır.","İnternetin yaygınlaşması pek çok zararını da beraberinde getirmektedir."],"answer":"A","solution":"Doğru cevap A seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Ana düşünce","difficulty":"Orta","outcome":"Ana düşünce","text":"(I) Yaşananlar ve onların bıraktığı izler; acı çekerek\nöğrenilen, düşünerek bir karara varılan zamanların\nbütünü tecrübeyi oluşturur. (II) İnsan ömrü oldukça\nkısadır. (III) İnsanlar daha hızlı ve kolay gelişme kaydetmek için diğerlerinin tecrübelerinden yararlanmayı\nbilmelidir. (IV) Herkes mesleğinde ve hayatında, birçok\nkaranlık yoldan geçmek mecburiyetindedir ancak bu\nyolları elinde bir ışık olmadan geçmeye çalışmaktansa\nbaşkalarının daha önce uğraşıp yaktığı meşalelerinden istifade ederek yürümek, daha kolay ve daha kârlı\ndeğil midir?","stem":"Bu metnin ana düşüncesi numaralanmış cümlelerden hangisidir?","options":["I","II","III","IV"],"answer":"C","solution":"Doğru cevap C seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"Ünlü müzisyen Frank Sinetra’ya “Nasıl Sinetra olunur?”\ndiye sorduklarında şöyle cevap vermiş: “Sahneye çıktığım ilk gün, bugün bulunduğum yere gelmeyi kafaya\nkoymuştum. Siz de böyle yapın. Örneğin bir şirkette\nayak işlerine bakıyorsanız kendinizi ilk günden patron\nkoltuğunda görmeye başlamalısınız.”","stem":"Bu metinden yola çıkılarak Sinetra gibi başarılı olmanın neye bağlı olduğu söylenebilir?","options":["Başarılı kimselerin izinden gitmeye","En başından hedefi büyük tutmaya","Yavaş ve emin adımlarla ilerlemeye","Moral bozan insanları umursamamaya"],"answer":"B","solution":"Doğru cevap B seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Yardımcı düşünce","difficulty":"Orta","outcome":"Yardımcı düşünce","text":"“İnsan İnsana” benim ilk kitabımdır. İnsan ilişkilerinin trenin rayında gittiği gibi düz bir yolda\ngitmediğini bizzat tecrübe ettim. İnsan ilişkileriyle\nilgili çocukluğumda gördüğüm ve öğrendiğimin\nötesinde yeni bilgilere ve tutumlara gereksinim\nduyduğumu anladım. Araştırdım, okudum, düşündüm ve uyguladım. Öğrendiklerimi bu kitapta\npaylaştım. İletişim alanına ilk adımı atanlara önerilecek bir kitap bu. Kitapta çizgi ustası Erdoğan\nBozok’un çizimlerinden ve mizah ustası Aziz Nesin’in öykülerinden istifade ettim.","stem":"Bu metnin yazarının sözünü ettiği kitabıyla ilgili\naşağıdakilerden hangisi söylenemez?","options":["Yazıldığı alanda başlangıç kitabı sayılabileceği","Deneyimleyerek edindiği bilgilerden oluştuğu","Okuyucusuna sıra dışı bir bakış açısı kazandırdığı","Alanında uzman bazı isimlerin katkısını içerdiği"],"answer":"C","solution":"Doğru cevap C seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"200’den fazla farklı kuş türü gerçekleştirdikleri zorlu\nyolculuğu tamamlayabilmek için Kıbrıs’ta mola verir,\nyola devam edebilmek için yağ depolar. Bunlar adaya\nuğrayan göçmen türlerdir. Sayılarının bu kadar çok olması Kıbrıs’ın göçmen kuşların göç yolunun ortasında\nyer almasından kaynaklanır. Bu kuşlar arasında pek\nçok değişik tür sayılır: aladoğan, şahin, balaban, taş…","stem":"Bu metinde aşağıdaki sorulardan hangisinin cevabı yoktur?","options":["Göçmen kuşlar göç ederken niçin mola verir?","Kıbrıs’ta mola veren göçmen kuşlardan bazıları\nhangileridir?","Göçmen kuşların Kıbrıs’ta mola vermesinin sebebi\nnedir?","Kıbrıs’ta mola veren göçmen kuşlar hangi güzergâ-\nhı kullanır?"],"answer":"D","solution":"Doğru cevap D seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"","stem":"Ağlama artık, aynalar kırılacak içimde\nBulutlara değdirme ellerini, ne olur\nSanki görmüş gibisin bir pencere önünde\nSessiz hıçkırıklara gömülen bedenimi\nRuhuma dokunduğun fırtınalı bir günde\nAğlama, bakışların deli divane olur\nBu dizelerde aşağıdakilerden hangisi yoktur?","options":["Endişe","Üzüntü","Tahmin","Pişmanlık"],"answer":"D","solution":"Doğru cevap D seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"Kuşlar arasında yarasa ne ise düşünceler arasında da\nkuşku odur. İkisi de hep alaca karanlıkta uçar. Kuşkularımızı baskı altında tutmak, hiç değilse gözaltında\nbulundurmak zorundayız. Aksi takdirde kuşkular kafamızı bulandırır, arkadaşlarımızı yitirmemize yol açar,\nişimizi altüst eder. Kralları zorbalığa, bilge kişileri bocalamalara ve kara düşüncelere sürükler.","stem":"Bu metne göre aşağıdakilerden hangisi kuşkunun\nözelliklerinden biri değildir?","options":["Ruhsal bunalıma sokması","Gece yarısı ortaya çıkması","Sosyal ilişkilere zarar vermesi","İradeyle kısıtlanabilmesi"],"answer":"B","solution":"Doğru cevap B seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"• Sinema salonları nasıl bu kadar sessiz oluyor?\n• Çalar saat yokken insanlar nasıl uyanırdı?\n• Uğur böceği ismi nereden geliyor?\n• Ağaçlar neden yaprak döker?","stem":"Aşağıdakilerden hangisi bu soruların herhangi biriyle ilişkilendirilemez?","options":["Yaprakları yiyen yaprak bitleri başta olmak üzere,\ntarım ürünlerine zarar veren onlarca böceği yiyerek\nbitkilerin verimsizleşmesine ve kurumasına engel\nolan böcekler, tarlalara bereket getirdiği için çiftçilerimiz tarafından “uğur böceği” adını almıştır.","Bazı ağaçlar sonbaharda yapraklarının hepsini\ndöker. Bazılarıysa yıl boyunca yapraklarının bir bölümünü döker ve yeni yapraklar çıkarır. Yapraklarını\nyenileyen bu ağaçlar yapraklarının hepsini aynı anda dökmediği için hep yeşil görünür.","Sinema salonlarının duvarları sesin yankılanmaması, dışarıdaki seslerin içeri girmemesi, içerideki\nseslerin de dışarı çıkmaması için sesi emen, yumuşak ve girintili çıkıntılı malzemelerle kaplanır.","Saatin icadından önce, belirli bir süre boyunca\nyanmaya ayarlanan mum saatleri vardı. Hatırlatıcı\nveya alarm kurmak istediğinizde istediğiniz zamana\ndenk gelecek şekilde muma bir çivi tutturuyordunuz ve mum o seviyeye kadar eridiğinde çivi metal\nmumluğun üzerine düşüp ses çıkararak sizi uyarıyordu."],"answer":"B","solution":"Doğru cevap B seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"Bir romanı okurken elbette konusunun ilgimizi çekmesi\nkadar edebî lezzete sahip olmasını bekleriz. Açıkçası damak tadı ararız. Şüphesiz içinde bulunduğumuz\nruh hâli de önemlidir. Söz gelimi insanın psikolojik\nyönden kötü bir devresinde iyi gidebilecek romanlardan da söz edildiğini duymuş olmalısınız. Böyle bir\ndönemde sürükleyicilik aranmayabilir. Durağan bir\natmosfere sahip, başka bir zaman olsa sıkıntıdan patladım diyeceğiniz bir roman kafa dağıtmak için ideal\nhâle gelebilir. Şüphesiz bu istisnai bir durum olmalı.\nGenellikle akıcılığı, damak zevkimize uygunluğunu\nönemseriz elbet. Ayrıca daha önceden bilip tanıdığımız ve beğendiğimiz bir yazarın yeni bir romanı olması\nda bize rehberlik edebilir. Son zamanlarda okuduğum\nbir romanı bu anlamda ele aldığımda yazarı açısından\nbenim için bildik bir eser değildir. Açıkçası tavsiye edilmesi üzerine okuduğumu söylemeliyim.","stem":"Bu metinde aşağıdaki sorulardan hangisinin yanıtı\nyoktur?","options":["Kitap okuma zevki ruh hâlimizle yakından ilgili midir?","Size birilerinin önerdiği kitapları da okur musunuz?","Okuduğunuz kitaptaki sürükleyicilik olmasa olmazınız mıdır?","Okuduğumuz kitapları tanıttığınız yazılarınız var mı?"],"answer":"D","solution":"Doğru cevap D seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Yardımcı düşünce","difficulty":"Orta","outcome":"Yardımcı düşünce","text":"Bugünlerde neredeyse tüm gündem “Pokemon\nGo” oyunu üzerinde yoğunlaşmış. 90’lı yılların vazgeçilmez çizgi filmi, şimdilerde bir oyun olarak geri\ndöndü. Hem de tüm dünyayı bir anda sarsarak...\nOyun kısa sürede dünyaya yayıldı. Hatta ülkemizin\nbazı kentlerinde bu oyunu oynayan gençler sokaklarda sabahladıklarından belediye başkanlarından\nşarj istasyonları istemeye başladı. Peki, “Pokemon\nGo”yu bu seviyeye getiren etken neydi? Elbette ki\nkendinden öncekilerden tamamen farklı olmasıydı.\nİnsanlar Pokemon avlamak için aynı zamanda dışarı çıkıyor ve insan kalabalıklarının arasına giriyor.\nYani bir tür sanal gerçekçilik durumu söz konusu.","stem":"Bu metinden “Pokemon Go” oyunuyla ilgili aşağıdakilerin hangisine ulaşılamaz?","options":["Gerçek dünyanın bir parçası olarak geliştirildiğine","Pek çok gençte bağımlılık oluşturduğuna","Kullanıcılarını zamanla sosyalleştirdiğine","Popüler bir çizgi filmden esinlenildiğine"],"answer":"C","solution":"Doğru cevap C seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"• Ateşi söndürmek için neden yaygın olarak başka\nmaddeler değil de su kullanılır?\n• Alevlerin arkasındaki görüntü neden bulanık olur?\n• Su neden yanmaz?","stem":"Aşağıdakilerden hangisi bu soruların herhangi biriyle ilişkilendirilemez?","options":["Ateşin ısıttığı havanın yoğunluğu düşer. Bu nedenle\nsıcak hava yükselir. Işık, yoğunluğu farklı olan bir\nortama geçtiğinde kırılır. Bu da görüntünün netliğini\nkaybetmesine ve çalkantılı hâle gelmesine yol açar.","Ateşin yanması için oksijen gereklidir. Ateşle oksijenin ilişkisini kesmek için su ve kum gibi maddeler\nya da ateşe dayanıklı bir örtü gerekir. Ancak en etkili söndürme malzemesi sudur. Çünkü su, ateşin\noksijenle bağlantısını da kesmenin yanında kaynağını da soğutur.","Mumun üzerine bir kavanoz kapattığınız zaman\nalev söner, yanması için oksijen lazımdır. Mum yanarken alevin orta kısmına pek oksijen gitmez. Bu\nyüzden daha koyu renkte görünür. Ancak alevin bol\noksijen alan dış kısmı ve üstü daha canlı yanar.","Doğada bulunan veya yapay olarak elde edilen,\nçoğu organik bileşikler olan birçok madde; hava\nve oksijen gibi gazlarla oksitlenerek ısı verir. Bir\nmaddenin ateş durumuna geçmesi için oksijenle\nkimyasal reaksiyon verebilecek ürün olması gerekir.\nSu içinde ise böyle bir ürün yok."],"answer":"C","solution":"Doğru cevap C seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Yardımcı düşünce","difficulty":"Orta","outcome":"Yardımcı düşünce","text":"Türk geleneğinde kızların çeyizi, evlenene kadar sandık\niçinde saklanır ve gelinin evine de sandıkta taşınırdı.\nVarlıklı ailelerin gelin sandıkları masif ağaçtan sedef\nkakmalı, telkâri süslemeli veya oymalı mobilyalardı.\nÇeyiz sandığı süslemeleri toplumlara göre değişen\n-doğum, bereket, şans gibianlamlar içerebilir. Türkler, yeni kurulan aile için bereket dilemek amacıyla\nçeyiz sandıklarında daha çok bitki, çiçek motifleri işlemişlerdir.","stem":"Bu metinden aşağıdakilerden hangisi çıkarılamaz?","options":["Sandık; gelinin ve ailesinin varlığını, sosyal statüsünü ifade eden bir araçtır.","Türk çeyiz geleneğinde sandık süslemelerinin vermek istediği mesajlar vardır.","Çeyiz sandığı, evlenme âdetleri içindeki önemini\nhâlâ korumaktadır.","Sandık, çeyizin depolanıp uzun süre muhafaza\nedilmesini sağlar."],"answer":"C","solution":"Doğru cevap C seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Yardımcı düşünce","difficulty":"Orta","outcome":"Yardımcı düşünce","text":"","stem":"Ben şairim. Bir arı gibi türlü türlü çiçeklerden toplarım\nbalımı. Arının konduğu tüm çiçekler sarı mı ki şiirlerimdeki kelimelerin hepsi Türkçe olsun! Şiirde anlam\narayışında olan da benim şiirimi okurken sözlükleri karıştırsın bir zahmet! Şiir anlayışım bu benim. Bu\nyüzden şiirlerimi okumayacaklara uğurlar olsun! Şiirimi\nhiçbir zaman ihtiyaçlarımı karşılayacak bir kaynak olarak görmedim ben.\nDüşüncelerini bu şekilde dile getiren şairle ilgili\naşağıdakilerden hangisi söylenemez?","options":["Şairlikten maddi kazanç beklentisi yoktur.","Şiirlerinde yabancı sözcükler kullanır.","Okuyucu kaybetme kaygısı duymaz.","Şiirlerini bilgili kişilerin okumasını ister."],"answer":"D","solution":"Doğru cevap D seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Yardımcı düşünce","difficulty":"Orta","outcome":"Yardımcı düşünce","text":"Yaklaşık 300 milyon yıl önce Dünya’da şu anki gibi\nyedi kıta yerine Pangea isimli tek bir süper kıta vardı. Pangea günümüzden yaklaşık 175 milyon yıl önce\nparçalanmaya başladı ve bugün yeryüzündeki yedi\nana kıta bu parçalanmanın sonucu oluştu. Birkaç yüz\nmilyon yıl sonra ise kıtalar tekrar birleşip yeni bir süper\nkıta oluşturabilir.","stem":"Bu metinden aşağıdakilerden hangisi çıkarılamaz?","options":["Üzerinde bulunduğumuz kıta, Pangea’nın bir parçasıdır.","Kıtalar, bulunduğu noktada sabit değildir.","Pangea yedi parçaya bir seferde bölünmüştür.","Dünya’nın milyonlarca yıllık geçmişi vardır."],"answer":"C","solution":"Doğru cevap C seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"Günümüzdekiler, dijital fotoğraf makinelerinin onları\nprofesyonel fotoğrafçı yapmaya yeteceğini düşünüyor. Yani dijital fotoğraf makinesi alan herkes kendini\nprofesyonel fotoğrafçı ilan ediyor. Tarihin en büyük\nfotoğrafçılarının ellerinde bugünkü makineler yoktu\nama unutulmaz fotoğraflar çektiler. İyi fotoğrafçıların\nmayasında eğitim, emek, sanatsal bakış açısı, öngörü,\nheyecan, hırs ve azim vardır.","stem":"Bu parçadan,\nI. Gelişen teknolojinin sunduğu imkânlar iyi bir\nfotoğrafçı olmak için yeterli değildir.\nII. Başarılı fotoğrafçılar kötü makinelerle dahi harika\nkareler çıkaran kişilerdir.\nIII. Dijital fotoğraf makineleriyle birlikte fotoğrafçılık bir\nsanat dalı olmaktan çıkmıştır.\nyargılarından hangileri çıkarılabilir?","options":["Yalnız I","I ve II","II ve III","I, II ve III"],"answer":"B","solution":"Doğru cevap B seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Yardımcı düşünce","difficulty":"Orta","outcome":"Yardımcı düşünce","text":"Shakespeare; tiyatronun insanı, insana, insanla, insanca anlatma sanatı olduğunu söyler. Olayları oluş\nyoluyla gösteren tiyatro bu yönüyle konuşmaya ve eyleme dayanır. Diğer edebî eserler okumak ve dinlemek\niçin yazılmışken tiyatro oyunu sahnede seyirci önünde\noynanır. Tiyatro metni, tiyatronun edebiyat ögesidir.\nBu edebiyat ögesi yanında tiyatro kavramı içinde;\noyuncu, sahne düzeni, ışıklandırma, dekor, kostüm ve\nmüziğin bütünlüğü söz konusudur.","stem":"Bu metinde tiyatro ile ilgili aşağıdakilerden hangisine değinilmemiştir?","options":["Unsurlarına","Tanımına","Ayırt edici özelliğine","Türlerine"],"answer":"D","solution":"Doğru cevap D seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"Okçuluk, okun bir yay aracılığıyla hedefe gönderildiği spordur. Dünya çapındaki araştırmalar okçuluğun\npek çok farklı kültürü birleştiren küresel bir etkinlik\nolduğunu ortaya koymaktadır. Okçuluk sporunda\noyuncular çeşitli mesafelerden sarı, kırmızı, mavi ve\nsiyah renklerle iç içe tasarlanmış halkalardan oluşan\nhedefi vurarak en yüksek puanı almak için mücadele\nederler. Dolayısıyla rakipten ziyade kendileriyle yarışırlar, yaptıkları her atışta daha iyisini elde etmeye\nçalışırlar.","stem":"Bu metinde aşağıdaki sorulardan hangisinin cevabı yoktur?","options":["Okçuluk sporunda amaç nedir?","Okçulukta sporcu hangi özellikleri taşımalıdır?","Okçuluk sporu yerel midir, evrensel midir?","Okçuluk nedir?"],"answer":"B","solution":"Doğru cevap B seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"Yeşil bitkilerin su, toprak ve havadaki atıkları arıtmak\nve kontrol etmek için kullanılmasına fitoremediasyon deniliyor. Bu süreçte enerji kaynağı olarak güneş\nenerjisinden yararlanıldığı için bu yöntem hayli düşük\nmaliyetli. Ayrıca çeşitli kirleticilerin temizlenmesinde\nde etkili bir şekilde kullanılabiliyor. Hardal bitkisi, sakız\nağacı, ayçiçeği, yulaf bitkisi, çayır otu ve domuz otu\ngibi birçok bitkinin zararlı atık sahalarında aşırı biriken\nkirleticilerin temizlenmesinde başarılı olduğu kanıtlandı. Dünya çapında metaller, böcek ilaçları, ham petrol\nve türevleri gibi kirletici maddelerin fitoremediasyon\nyöntemiyle temizlenmesine yönelik projeler geliştiriliyor.","stem":"Bu metinde aşağıdaki sorulardan hangisinin cevabı yoktur?","options":["Fitoremediasyon nedir?","Fitoremediasyon işlemi ne kadara mal olmaktadır?","Hangi bitkilerin zararlı atık sahaları fitoremediasyon\nile temizlenebilmektedir?","Hangi maddelerin fitoremediasyon yöntemiyle temizlenmesi planlanmaktadır?"],"answer":"B","solution":"Doğru cevap B seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"Yaz kış demeden yerli yabancı turist akınına uğrayan\nbir köyde yaşıyorum. Burada yetişen benzersiz zeytin,\nüzüm ve meyveleri bir yiyen bir daha geliyor. Üzümün\nreçelinden pekmezine, içeceğine kadar her şeyi yapılır\nburada. Doğaya hiçbir müdahalede bulunulmamış bu\nköyde 19. yy. sonu ve 20. yy. başlarına ait, görenlerin hayran kaldığı taş evler hâlâ kullanılmakta. Yerel el\nsanatları tüm canlılığı ile devam ettirilirken burada yaşayanlar asla değiştirmedikleri dilleri, giyim kuşamları,\nyemekleri yani geleneksel yaşamları ile son derece\ndikkat çekmektedir.","stem":"Aşağıdakilerden hangisi metinde bahsi geçen yerin çokça ziyaret edilmesinin sebeplerinden biri\ndeğildir?","options":["Tarım ürünlerinin kalitesi ve tarım ürünlerine dayalı\nüretim çeşitliliği","Özgün mimari dokunun korunmuş olması","Köyün önemli kültür ve turizm merkezlerine olan\nyakınlığı","Orijinal kültürel unsurların ön planda olması"],"answer":"C","solution":"Doğru cevap C seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"Bir genç kız, her şeyi bilen bir bilgeyi şaşırtmak için bir\nplan yapıyor. İki elinin arasına bir kelebek koyacak ve\nbilge adama “Avucumun içinde bir kelebek var. Canlı\nmı, ölü mü?” diye soracak. Bilge adam her ne derse\ntersini ispat etmiş olacak. Kız, planını hayata geçirmek\nüzere bilgeye gidiyor. Kapalı tuttuğu ellerini bilgeye\ndoğru uzatıyor ve sorusunu yöneltiyor. Bilge kızın gözlerinin içine uzun uzun bakıyor ve cevap veriyor: “Canlı\nya da ölü olması senin ellerinde kızım, senin ellerinde.”","stem":"Bu hikâyenin unsurlarıyla ilgili aşağıdakilerden\nhangisi doğrudur?","options":["Olay, bilge adamın evinde geçmektedir.","Anlatım birinci kişi ağzından yapılmıştır.","Hikâyedeki olay, bilge adamın şaşırmasıdır.","Olayın gerçekleştiği zaman belirsizdir."],"answer":"D","solution":"Doğru cevap D seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"Mutlu, Sefa ve Caner adlı üç arkadaş golf oynuyormuş. Mutlu’nun yaptığı atışta top çimlere ulaşabilmiş.\nSefa daha uzun bir atış yapmış. Onun vurduğu top da\nküçük bir gölcüğün içine düşmüş. Sıra Caner’e gelmiş.\nGüneşin tam tepede olduğu sırada Caner’in vurduğu top doğrudan çitlere çarpıp yola fırlamış, o sırada\nyoldan geçen bir kamyondan sekip golf sahasındaki\nçiçeklerin arasına düşmüş. Çiçeklerin arasındaki bir\nkurbağa topu görür görmez atılıp ağzına alıvermiş.\nTam o sırada bir kartal süzülerek gelmiş ve kurbağayı\nkapmış ve yükselmiş. Kartal, pençelerinde kurbağayla golf sahasının ucuna doğru ilerlerken kurbağa topu\nağzından bırakmış ve top süzülerek doğrudan deliğe\ngirmiş.","stem":"Bu metnin hikâye unsurları ile ilgili aşağıdakilerden\nhangisi yanlıştır?","options":["Olay: Üç arkadaşın golf oynaması","Yer: Golf sahası","Zaman: Öğle vakti","Kişi ve varlık kadrosu: Üç arkadaş, kamyoncu, kurbağa ve kartal"],"answer":"D","solution":"Doğru cevap D seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"Yetmişine merdiven dayayan yaşlı adam, daha uzun yaşayabilmek için yaşam tarzını tamamen değiştirmeye karar verir.\nSıkı bir diyete giren ve spor salonuna düzenli bir şekilde giderek üç ayda tam on kilo verir. Göbeği on santim daralırken\ngöğüs kafesi beş santim genişler. İyice dinçleşen yaşlı adam başarısını yepyeni bir saç modeliyle taçlandırmaya karar\nverir. Sabah randevulaştığı berberden öğleye doğru yeni saç modeliyle çıkarken berbere giren oğlu onu tanıyamadan\nyanından geçer. Babasını ancak sesinden tanıyan genç adamın şaşkınlığı görülmeye şayandır.","stem":"Bu parçadaki olay, yer, zaman ve kişiler aşağıdakilerin hangisinde doğru verilmiştir?\nOLAY YER ZAMAN KİŞİ","options":["Oğlunun yaşlı adamı tanımaması Berber dükkânı Sabah Yaşlı adam, berber ve yaşlı adamın\noğlu","Oğlunun yaşlı adamı tanımaması Berber dükkânı Öğle Yaşlı adam ve oğlu","Yaşlı bir adamın uzun yaşama isteği Spor salonu Öğle Yaşlı adam ve oğlu","Yaşlı adamın düzenli spor yapması Berber dükkânı Sabah Yaşlı adam ve oğlu"],"answer":"B","solution":"Doğru cevap B seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Yardımcı düşünce","difficulty":"Orta","outcome":"Yardımcı düşünce","text":"(I) İş makineleri gürültüyle geldiklerine göre gün doğmak üzereydi. (II) Evimizin hemen önünden geçen\nyolun kenarında ne kadar ağaç varsa hiç acımadan\nsöküyorlar. (III) Babamı ağaçları kesen işçilerin yanında\ngörünce tüm gücümü toplayıp oraya doğru koştum.\n(IV) Yanılmamıştım; canım babam, birkaç kişiyle beraber ağaçların kesilmesini engellemek için ağaçların\nönünde siper olmuştu.","stem":"Bu parçada numaralanmış cümlelerle ile ilgili\naşağı dakilerden hangisi söylenemez?","options":["I. cümlede olayın geçtiği zamanla ilgili bir çıkarımda\nbulunulmuştur.","II. cümlede ana olay hakkında bilgi verilmiştir.","III. cümlede kahramanlara ilişkin bilgi verilmiştir.","IV. cümlede olayın geçtiği mekân betimlenerek verilmiştir."],"answer":"D","solution":"Doğru cevap D seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"Hafta sonları bile gece gündüz çalışan bir adamdır\nbabam. Caminin önünden geçerken duvarının bir\nkısmının yıkıldığını görmüş, birkaç saat içinde onu\nonarmış, yanıma geldiğinde çok yorulmuştu. Eve giderken de beni bir ağaç altına oturtup Fatma teyzenin\nbahçesini suladı. Annem geciktiğimiz için söylenmesin\ndiye de bir demet çiçek topladı ona.","stem":"Bu parçada aşağıdaki hikâye unsurlarından hangisi belirsizdir?","options":["Zaman","Yer","Kişiler","Olay"],"answer":"A","solution":"Doğru cevap A seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"• Olay, kişi, zaman ve yer unsurları kullanılmıştır.\n• Anlatım birinci kişi ağzından yapılmıştır.","stem":"Aşağıdaki metinlerin hangisinde bu özelliklerin tümü yer almaktadır?","options":["1930’lu yılların başıydı. Dünyanın çoğu ülkesinde\nkadınlar oy kullanmazken biz “Ulu Önder”imiz sayesinde ilk kez oy kullanacaktık. Evimize en yakın\nokuldaki büyük çınar ağacın altında sıraya girdiğimizde birden Atatürk’ü karşımızda görmek bizi\nsevince boğmuştu. Bu okulda kullandığım ilk oyu\nhiçbir zaman unutmadım.","Serinlikte oturduğum balkonun altındaki ağacın\ndalları arasındaki kuşlardan sesler gelmeye başladı. Sonra bir iki kuş havalanıp tekrar dala konmaya\nve bağırmaya devam etti, ben de endişelendim.\nHemen eğilip ağaca baktım. Bir de ne göreyim! Bir\nyılan ağacın gövdesine sarılıp yukarı çıkıyor.","Küçük kız babasının omuzlarından sıkıca tutmuş\ngelen dalgalardan korunmaya çalışıyordu. Güneşin\nbatmasıyla deniz maviliğini kaybetmeye başlamıştı.\nAnnesiyle deniz kenarında oynayan kardeşi ise arada ablasına ve babasına bakarak el sallıyordu.","Abim incirlerin sabahın ilk saatlerinde toplanmasının daha iyi olacağı düşündüğünden o sabah da\nbizi erkenden uyandırmıştı. Topladığımız kovalarca\ninciri ne yapacağımızı düşünürken annem çoktan\nişe koyulmuştu. Kahvaltılarımızı süsleyecek enfes\nincir reçellerimiz olacaktı."],"answer":"A","solution":"Doğru cevap A seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"Kişiler : Ali, Recep, orman bekçisi\nZaman : Öğle saatleri\nYer : Orman\nOlay : İki çocuğun ormanı yanmaktan kurtarması\nAnlatıcı: III. kişi","stem":"Aşağıdakilerden hangisi bu yapı unsurlarına uygun olarak kurgulanmıştır?","options":["Köyün çobanları Ali ve Recep ormana ot toplamaya gitmiş, dönüş yolunda koyu bir sohbete dalmışlardı ki tiz hayvan\nsesleriyle irkildiler. Sesin geldiği yere koştuklarında birkaç ağacın yanmakta olduğunu, orman bekçisinin de bunları\nsöndürmeye çalıştığını görüp hemen yardıma koştular ve yangını yayılmadan el birliği ile söndürdüler.","Bekçisi olduğum ormanda teftişe çıkmıştım. Hafta sonu ormana gezmeye gelen çok olur, öğle saatlerinde burası\niyice kalabalıklaşırdı. Her şey yolunda, diye düşünürken söndürülmeden bırakılmış mangal korlarının çayırların bir\nkısmını tutuşturduğunu gördüm. Yardımıma koşan Ali ve Recep olmasaydı ormanı tek başıma kurtaramazdım.","Sınıfça pikniğe geldikleri ormanda dolaşmaya çıkmıştı Ali’yle Recep. Tam tepedeki güneşten kaçıp ağaçların gölgesinde dinlenirken burunlarına gelen yanık ot kokusuyla soluğu orman bekçisinin yanında aldılar. Bekçi anladı ki atılan\ncam parçaları mercek görevi görüp otları tutuşturmuştu. Çocukların dikkati sayesinde orman yanmaktan kurtuldu.","Ali ile Recep, ormandan odun toplamış; babalarının ardında köye dönüyorlardı. Kızgın güneşin altında soluğu kesilen Ali dinlenmek istedi. O sırada Recep ormandan yükselen dumanı gösterdi ve babaları koşarak orman bekçisini\nbuldu. Bekçi yetiştiğinde Ali ve Recep yangını söndürmüştü bile."],"answer":"C","solution":"Doğru cevap C seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"Olay : Bir gencin susuz bir köpeğe su vermesi\nYer : Otobüs durağı\nZaman : Yaz\nVarlık kadrosu : Yazar, yolcular, genç ve köpek\nAnlatıcı : I. kişi","stem":"Aşağıdaki metinlerden hangisi bu yapı unsurlarına uygun olarak kurgulanmıştır?","options":["Bir yaz günü, durakta otobüs bekliyorum. Bir köpek geldi, dili bir karış dışarıda. Yolcuların çoğu, dönüp köpeğe bakmadı bile. Bir genç, yandaki büfeden bir pet tabak aldı. Elindeki şişeden tabağa su doldurup köpeğin önüne koydu.\nKöpek, suyu büyük bir istekle içti.","Bir grup yolcuyla durakta otobüs bekliyoruz. Buram buram terliyoruz. Eee, boşuna dememişler “Ağustosun sıcağı,\nsanki fırın ocağı.” diye. Bir köpek yanaştı. Gençliğin verdiği çeviklikle yandaki marketten bir şişe su ve bir pet tabak\nalıp geldim. Suyu pet tabağa döktüm. Köpek, o suyu kana kana içti.","Genç, bir yaz günü durakta yazar arkadaşıyla otobüs bekliyordu. Derken susuz bir köpek paçasına yanaştı. Genç,\nyazara elindeki şişeyi uzattı. Yazar, gencin eline su döktü. Küçük köpek gencin avucundan kana kana su içti. Yolcular\nikilinin bu davranışını alkışladı.","Bu yaz otobüsle yolculuk yapıyordum. Bir durakta genç biri kucağında köpeğiyle bindi. Otobüs hareket etti. Bir süre\nsonra genç, köpeğinin susadığını anlamış olacak ki çantasından küçük bir kap çıkardı. Bu kaba elindeki şişeden su\ndöktü. Köpek suyu kana kana içti."],"answer":"A","solution":"Doğru cevap A seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"Uyanık köylünün biri, bir koyununu satmak için pazara gitmiş. Bir adam yanına yaklaşıp koyunun fiyatını sormuş. Köylü\nşöyle cevap vermiş: Ben bu koyunu beş altına aldım. Altı altına satmak niyetindeyim. Yok, bu kıymet hoşunuza gitmediyse size yedi altına satabilirim. Ancak koyunun asıl değeri sekiz altın olduğuna göre sizin bana dokuz altın vermeniz\ndaha doğru olur. Hemen alıp götürmek niyetindeyseniz. Buyurun, on altına koyun sizindir.","stem":"Bu metinde aşağıdaki hikâye unsurlarından hangisi belirsizdir?","options":["Olay","Zaman","Yer","Kişiler"],"answer":"B","solution":"Doğru cevap B seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"Ben harikalar diyarına geldim, diyerek dükkânda koşuşturmaya başladı Zehra. Burada her yer şekerle doluydu. Günün\nilk ışıklarının vurduğu cam kavanozlardaki renk renk şekerler, mücevher parçaları gibi parıl parıldı. Dükkân sahibi ne almak istediğini sorduğunda küçük kız, ellerini şaklatıp babasının gözlerinin içine bakarak “Hepsinden, hepsinden!” diye\nbağırdı. Onun bu hâli babasını da dükkân sahibini de güldürmüştü.","stem":"Bu hikâyedeki unsurlar aşağıdakilerin hangisinde doğru verilmiştir?\nOLAY YER ZAMAN KİŞİ ANLATICI","options":["Küçük bir kız ve babasının şeker\nalışverişi Şeker dükkânı Belirsiz Zehra, babası, şeker\ndükkânının sahibi I. kişi","Küçük kızın ilk kez şeker yeme\nmutluluğu Tatlıcı Öğle Zehra, babası III. kişi","Bir babanın küçük kızını şeker dükkânına getirmesi Dükkân Akşamüstü Zehra, şeker\ndükkânının sahibi I. kişi","Küçük bir kızın dükkânda gördüğü\nşekerler karşısında heyecanlanması Şeker dükkânı Sabah Zehra, babası, şeker\ndükkânının sahibi III. kişi"],"answer":"D","solution":"Doğru cevap D seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"","stem":"Aşağıdakilerden hangisinde hikâye unsurlarının tümüne (olay, yer, zaman, kişiler, anlatıcı) yer verilmiştir?","options":["Sokağın başındaki durakta dolmuş bekliyordum. Yaşlı bir kadının omzuma dokunmasıyla irkildim. Durakta onca\ninsan varken dolmuşun ne zaman geleceğini sormak için bula bula en kuytu köşede duran beni bulmuştu. Can sıkıntımı bastırıp nazikçe cevapladım sorusunu.","Karşımızda İstanbul Boğazı’nın eşsiz manzarası… Tüm kızıllığını gökyüzüne yayıp batmakta olan güneşin hüzünlü\nvedası eşliğinde ağabeyimle çocukluğumuzu yâd ederken kâh gülüp kâh ağlıyoruz. Evet, sahildeki bir banka oturduk, etraftakilere aldırmadan koca koca adamlar ağlıyoruz süratle geçen o yıllara.","Bugün hiç kitap okumadım. Ne sabah ne akşam… Dün de okumamıştım. Önceki gün de… Olacak iş değil! Kitaplarımla ben etle tırnak gibiyizdir hâlbuki. Toprakla yağmur gibiyizdir. Toprak olan ben muhtacım kitapların öz suyuna.","Site bahçesinin arka tarafında ahşap bir köpek kulübesi var. Bu, bir iki tahtanın çakılmasıyla yapılmış alelade bir\nkulübe değil; oymaları, süslemeleriyle âdeta bir sanat eseri. Kulübenin önündeki mama tasları bile ahşaptan özel\nolarak yapılmış."],"answer":"B","solution":"Doğru cevap B seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Yardımcı düşünce","difficulty":"Orta","outcome":"Yardımcı düşünce","text":"EFHİMA yani Efsaneler, Hikâyeler ve Masallar Ülkesi’ne uzanan rengârenk bir maceraya atılmaya hazır\nmısınız? Şayet isterseniz Sakız Sardunya’nın kendi\nağzından anlatacağı maceraları tam size göre! İstanbul’da sakin bir mahallede yaşayan bu kız ismini hiç\nmi hiç sevmezdi. Sakız Sardunya, hem akıllı hem meraklıydı. Bir atlası vardı sürekli karıştırdığı ve pek çok\nkitabı... Hayaller kurmaya bayılırdı. Bir gün okulun\nkütüphanesinde hiç beklemediği bir sürprizle karşılaştı. Rafların arasında tuhaf bir küre parlıyordu. Bulan\nherkesi unutulmayacak bir yolculuğa çıkaran sihirli bir\nküre!","stem":"Bu metinden hareketle “Sakız Sardunya” adlı kitapla ilgili aşağıdakilerden hangisine ulaşılamaz?","options":["Hedef kitlesine","Yer ve şahıs unsurlarına","Anlatıcının kaçıncı kişi olduğuna","Anlattığı olaya"],"answer":"A","solution":"Doğru cevap A seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Yardımcı düşünce","difficulty":"Orta","outcome":"Yardımcı düşünce","text":"Keçiciğin aklı bir karış havada, sürüsünü bir yana bırakmış, otlaya otlaya çıkmış bir dağ başına. Hain koca\nkurt görmüş keçiciği. Keçicik “Eh, ne yapalım; bari bana biraz kaval çal ki neşeleneyim.” demiş. Kurt “Son\nisteği zavallının.” diye düşünmüş. Bulmuş bir kaval,\n“Füyt, füüyt!” çalmaya başlamış. Kurt çalmış, keçicik\noynamış. Derken ötelerden kaval sesini duyan köpekler koşturmuşlar; gelmişler, kurdu önlerine düşürüp bir\ngüzel kovalamışlar.","stem":"Bu hikâyenin unsurlarıyla ilgili aşağıdakilerden\nhangisi söylenemez?","options":["Olayın gerçekleşme zamanı belirsizdir.","Olay; keçinin, aklını kullanarak kurdun elinden kurtulmasıdır.","Kahramanlar; keçi, kurt, çoban ve köpeklerdir.","Anlatım III. kişi ağzından yapılmıştır."],"answer":"C","solution":"Doğru cevap C seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Konu bulma","difficulty":"Orta","outcome":"Konu bulma","text":"","stem":"Aşağıdaki dizelerden hangisinde kurgusal anlatım söz konusu değildir?","options":["Silkinince ansızın\nDeğişir şekli kızın\nKuş olur, çiçek olur\nBazı kelebek olur","Yıldızlar ve dolunay olmadı mı\nGökyüzü de kördür\nYüreğindeki kara bulutlar\nDurmadan yıldırımlar kusar","Küçük bir serçe kuşu geldi\nHavuzun taşına kondu\nBir içti, bir doğruldu\nNasıl da korkuyordu","Günün tükendiği bu saatlerde\nTüm doğa canla başla çalışıyor\nGece vakti bu yıldızlardan inen\nNe acayip bir korkudur kim bilir"],"answer":"C","solution":"Doğru cevap C seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"","stem":"Aşağıdaki metinlerde anlatılanlardan hangisi hayal ürünüdür?","options":["Annem, babam, ağabeyim, babaannem, amcalarım, halalarım, yengeler beş katlı bir apartmanın çeşitli katlarında\nyaşıyorduk. Ben doğmadan bir yıl önceye kadar bir büyük Osmanlı ailesi gibi hep birlikte ayrı oda ve kısımlarında\nyaşadıkları yandaki büyük taş konak terk edilip özel bir ilkokula kiraya verilmiş.","Küçücük bir çocuktum, ilkokula yeni başlamıştım, yaz tatilindeydik. Dedemin bir eşeği vardı. Bir gün dedem “Gel!”\ndedi bana. “Seni gezmeye götüreceğim.” Beni eşeğin sırtına bindirdi. İpi eline aldı ve yürüdü. Epeyce engebeli ve\ndik, dağlı tepeli bir yola düştük.","Güneş altında uzun süre yürümek onu çok yormuştu. Etrafına baktı. Sığınacak bir yer ararken uzakta görkemli bir\nağaç gördü ve o kocaman ağacın gölgesine uzanıp minik perilerle birlikte ağacın anlattığı hikâyeleri dinledi.","Damla, her zaman bir köpeği olsun istiyordu. Onuncu yaş gününde sabah uyandığında başucunda hareket eden ve\nhavlayan bir kutu buldu. Kutuyu açtığında karşısında hoplayıp zıplayan, dili dışarıda sevimli bir yavru golden köpek\nvardı."],"answer":"C","solution":"Doğru cevap C seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"Şarkıların en güzelini senin olsun\nGüneşi, mavi denizi sen seyret\nSihirli bir değneğin olsun\nDokunduğun hayatlar renklensin\nGüzelliğin Kafdağı’nın ardından duyulsun\nBu ıssız çöllerde\nDikili hiçbir ağacı olmayan\nSenin yeşil gözlerinle canlansın","stem":"Bu şiirde geçen kurgusal unsurlar aşağıdakilerin\nhangisinde birlikte verilmiştir?","options":["Kafdağı – sihirli değnek","Issız çöl – mavi deniz","Yeşil gözler – sihirli değnek","Kafdağı – ıssız çöl"],"answer":"A","solution":"Doğru cevap A seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"","stem":"Issız dağlarda gezer, yokmuş izinden eser\nBazen göründüğü yer, bir sihirli pınarmış\nYüzü pembe bir şafak, gülse güller açacak\nYaşarmış elden uzak, dostları çobanlarmış\nBu dizelerdeki kişinin,\nI. Çobanlarla dost olması\nII. Herkesten uzakta yaşaması\nIII. Sihirli pınarlarda görülmesi\neylemlerinden hangileri hayal ürünüdür?","options":["Yalnız I","Yalnız III","II ve III","I, II ve III"],"answer":"B","solution":"Doğru cevap B seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"Yoğun dikkat sonucu oluşan zihinsel yorgunluğu giderebilmek için pencereden görünen manzaraya birkaç\ndakika bakmak yeterli olacaktır. Bu olanaktan yoksunsanız yani penceremizden dışarı bakacak manzaranız\nyoksa masanızın üzerine bir çiçek, bir doğal obje, bir\nmanzara resmi koyabilirsiniz. Çünkü insanlar biyolojik\nolarak su, ağaç ve yeşil ortamlara olumlu tepki verecek şekilde donatılmıştır.","stem":"Bu metindeki altı çizili ifadenin yerine aşağıdakilerden hangisi getirilebilir?","options":["ancak","son olarak","başka bir deyişle","özellikle"],"answer":"C","solution":"Doğru cevap C seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"Sanıyorum 1962 yılında, yurdun çeşitli bölgelerinde\n- - - - Trakya’da korkunç bir kış yaşandı. Gazete bu\nmüthiş kışın etkilerini yansıtmak amacıyla foto muhabiriyle birlikte en parlak haber muhabirini otomobille\nTrakya’ya göndermişti. - - - - karanlık bastığında gittikleri yol kardan kapanmış, geri dönme olanağı da\nkalmamıştı.","stem":"Bu metinde boş bırakılan yerlere sırasıyla aşağıdakilerden hangisi getirilmelidir?","options":["özellikle - Özetle","ilk olarak - Fakat","başka bir deyişle - Ama","özellikle - Ancak"],"answer":"D","solution":"Doğru cevap D seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"Hepimizin hâfızasında “belirli gün ve haftalar”a dair\nhâtıralar vardır. Belirli gün ve haftalar özellikle ilköğretim öğrencilerinin eğitim-öğretim hayatını parsel parsel\nele geçirmiş gibidir. Hemen her hafta, belirlenmiş bir\ngün bütün memlekette aynı edayla kutlanır; anılır.","stem":"Bu metindeki altı çizili ifadenin kullanım amacı\naşağıdakilerden hangisidir?","options":["Düşüncenin yönünü değiştirmek","Anlatımı desteklemek ve açıklamak","Konuyu özetlemek","Önem belirtmek"],"answer":"D","solution":"Doğru cevap D seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"Yaşadığımız kentin müzelerinde öğrenciler görürüz,\nbirkaç arkadaşları ile veya tüm sınıf olarak öğretmenleriyle gezmeye gelmişlerdir. Mesleğim gereği sık sık\nkarşılaştığım bu öğrencileri gözlemlediğimde çevrelerine üstünkörü baktıklarını gördüm. - - - - artık yalnızca\ncep telefonlarının ekranından bakıyorlar, diyebilirim.\nAslında kim tarafından, kaç yılında yapılmış gibi bilgiler\nkısa bir süre sonra unutulup gider. - - - - yaşadıkları\nkentin geçmişini, eski eserlerin neden korunması gerektiğini öğrenmeleri daha öncelikli olmalı.","stem":"Bu metinde boş bırakılan yerlere sırasıyla aşağıdakilerden hangisi getirilmelidir?","options":["Hatta - Oysaki","Özellikle - Ancak","Çünkü - Fakat","Üstelik - Başka bir deyişle"],"answer":"A","solution":"Doğru cevap A seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"Oyun, çocuğun gelişiminin merkezinde yer alır. Çocuklar oyun yoluyla etraflarındaki hayatı ve dünyayı\ntecrübe eder ve öğrenirler. Başka bir deyişle, oyunlar\nsırasında deneyimledikleri eğlenceli anlarda fiziksel\nçevrelerini keşfeder, duygularını ifade ederler.","stem":"Bu metindeki altı çizili ifadenin kullanım amacı\naşağıdakilerden hangisidir?","options":["Konuyu özetlemek","Anlatımı desteklemek ve açıklamak","Düşüncenin yönünü değiştirmek","Ana fikri vurgulamak"],"answer":"B","solution":"Doğru cevap B seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"Masallar, - - - - okul öncesi ve okula yeni başlayan\nbütün çocukların büyük ölçüde ilgisini çekmektedir. Masalların gizemli havası, serüven dolu fantastik\nolaylar içermesi, çoğunlukla iyilerin kazanıp kötülerin\nyenilgiye uğratılması masalları çocuklar için cazip kılmaktadır. - - - - masallar çocukların iç dünyasına yakın\nbir dünya sunmaktadır.","stem":"Bu metinde boş bırakılan yerlerden herhangi birine,\nI. Özellikle\nII. Başka bir deyişle\nIII. Ancak\nifadelerinden hangileri getirilirse metnin anlam bütünlüğü bozulur?","options":["Yalnız I","Yalnız III","I ve II","II ve III"],"answer":"B","solution":"Doğru cevap B seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"Geçen yaz, ihtiyar buzdolabımız ilk olarak hırıltılı bir ses çıkardı. Fakat babam bunu çok dert etmedi. Ardından huzursuz edici, tuhaf birtakım gürültüler çıkarmaya başladı. Babam bunu da çok dert etmedi. Son olarak\nbuzdolabımız sinir bozucu bir “tıs” sesi çıkarmaya başladı. Babam bu sesi de çok dert ediyor gibi görünmüyordu.\nAncak annem sesi fena hâlde umursuyordu ve sonunda olaya el koydu. Böylece eve yepyeni bir buzdolabı geldi.\nIV\nI II\nIII","stem":"Bu metinde altı çizili geçiş ve bağlantı ifadeleriyle ilgili aşağıdakilerden hangisi söylenebilir?\nI II III IV","options":["Olayları sıralar. Düşüncenin yönünü değiştirir. Olayları sıralar. Düşüncenin yönünü değiştirir.","Açıklayıcıdır. Düşüncenin yönünü değiştirir. Açıklayıcıdır. Düşüncenin yönünü değiştirir.","Olayları sıralar. Önem belirtir. Olayları sıralar. Önem belirtir.","Destekleyicidir. Düşüncenin yönünü değiştirir. Destekleyicidir. Düşüncenin yönünü değiştirir."],"answer":"A","solution":"Doğru cevap A seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"","stem":"Aşağıdakilerin hangisinde altı çizili geçiş ve bağlantı ifadesi düşüncenin yönünü değiştirmemiştir?","options":["Siz kitaplarınızı hem yazıyor hem resimliyorsunuz. Oysa genelde yazarlarla çizerler resimli kitaplar için iş birliği yapıyor.","Orijinali 1942 yılında yayımlanan kitabın Türkçeye -o dönemin şartlarını göz önünde bulundurduğumuzda- “hızlı”\nçevrildiğini söyleyebiliriz. Ancak nedense sonrasında yeni bir baskısı yapılmamış.","Feridun Oral’ın kitapları, Türkiye’de orta sınıftan çocuklar için büyük şanstır. Fakat kitapların sert kapak olmasına\nbağlı olarak yükselen fiyatları, bu kitaplara her çocuğun ulaşmasını zorlaştırmaktadır.","Ülkemizin ilk, dünyanın Londra’dan sonra ikinci en eski ve 1874’ten beri çalışan bir metrosu olduğunu biliyor muydunuz? Üstelik Karaköy’den Beyoğlu’na çalışan bu metro aynı zamanda dünyanın en minik metrosudur."],"answer":"D","solution":"Doğru cevap D seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"Yıllardır denize girdiğiniz kumsalın bir gün, zenginlerin\noturduğu tatil sitesinin güvenliği gerekçe gösterilerek\ntel örgülerle kapatıldığını görürseniz ne yaparsınız?\nİlçe belediyesi bu engelleri kaldırtmak için mahkemeye başvurmuş ama süreç uzayacağı için eli kolu bağlı\nbekliyor. - - - - yasalarda bu konuda herhangi bir boşluk yok. Sahillerimiz tümü ile halkın kullanımına açık\nolmalı. - - - - hemen her yerde bu tür uygulamalara\nrastlamak günlük yaşantımızın bir parçası olmuştur.","stem":"Aşağıdakilerden hangisi bu metindeki boşluklardan herhangi birine getirilemez?","options":["Çünkü","Hâlbuki","Ancak","Oysa"],"answer":"A","solution":"Doğru cevap A seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"I. Kuyunun ağzındaki halata bağlı demir kovayı kuyunun derinliklerine saldı.\nII. Böylece kovanın ağzına kadar su dolmasını sağladı.\nIII. Kovayı güçlükle yukarı çekerken suyun fazlası tekrar kuyunun içine dökülüyordu.\nIV. Gelen seslerden ve kovanın ağırlığından kuyuda\nçok az su birikmiş olduğunu anladı.\nV. Halatı sağa sola, yukarı aşağı sallayarak kovayı yan\nyatırdı.\nVI. Kuyunun çevresindeki birkaç kök salatalık, domates ve biberi sulamak için harekete geçti.","stem":"Numaralanmış cümlelerle anlamlı bir metin oluşturulduğunda hangisi dışarıda kalır?","options":["II","III","IV","V"],"answer":"C","solution":"Doğru cevap C seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"Bir grup araştırmacının geçtiğimiz günlerde yaptığı\nbir çalışma, kahverengi pelikanların - - - - gösterdi.\nPelikanlar uçarken dalgaların su yüzeyinin hemen üstündeki havayı hareket ettirmesiyle oluşan, yukarı\nyönlü hava akımını kullanıyor. Böylece kahverengi pelikanlar, kanat çırpmadan suyun hemen üzerinde daha\naz enerjiyle uzun mesafe uçabiliyor.","stem":"Bu parçada boş bırakılan yere anlam akışına göre\naşağıdakilerden hangisi getirilebilir?","options":["gaga yapılarının balık yakalamaya uygun olduğunu","doğadan nasıl yararlandıklarını","niçin güneyden kuzeye göç ettiklerini","kanat yapılarının su yüzeyinde süzülebilmeye uygun olduğunu"],"answer":"B","solution":"Doğru cevap B seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"K. Masadaki yerimi aldıktan sonra kahvaltı tabağıma iştahla sevdiğim yiyecekleri doldurmaya başlamıştım ki vızıltıya\nbenzeyen bir sesle irkildim.\nL. O sabah uyanıp bahçeye çıktığımda başıma geleceklerden habersizdim. Annemin hazırladığı nefis kahvaltı sofrasında yok yoktu: reçeller, kızartmalar, tuzlu yoğurtlar, biberli ekmekler…\nM. Evet, korktuğum başıma gelmişti. Birkaç arı önce masanın sonra da benim etrafımda dönmeye başladı. Annem\nsakin kalabilirsem arıların bana zarar vermeyeceklerini söylese de ben kahvaltı tabağımı alıp odamda kahvaltı yapmaya karar verdim.\nN. Küçükken arı sokması sonucu yüzüm şişmiş ve günlerce okula gidememiştim. Bu olay bende arılara karşı bir korku\noluşturmuştu. Endişeyle etrafıma bakınmaya başladım.","stem":"K, L, M, N harfleriyle gösterilen bölümlerle anlamlı bir metin oluşturmak istenirse doğru sıralama aşağıdakilerden hangisi olur?","options":["L - K - N - M","L - N - M – K","K - N - L - M","K - M - L - N"],"answer":"A","solution":"Doğru cevap A seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"SADIK USTA ― Komiserim, söylediğiniz çocuk bu mu?\nKOMİSER ― Evet, Sadık Usta. Bu çocuk sana iyi bir çırak olur. Öp ustanın elini bakayım.\nEROL ― Tabii, komiserim.\nSADIK USTA ― “Berhudar ol!” evladım. Akıllı bir çocuğa benziyor.\nKOMİSER ― Senden iyi olmasın, cin gibidir maşallah.","stem":"Aşağıdaki yay ayraç içi ifadelerden hangisi bu metnin herhangi bir yerinde kullanılamaz?","options":["(Erol’a dönerek)","(Kalem tutmuş narin ellerini öper.)","(Çocuğun başını okşayarak)","(Komisere döner.)"],"answer":"B","solution":"Doğru cevap B seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"Ormanın içindeyiz. Görkemli ağaçların arasında…\nRüzgâr püfür püfür esiyor, kuşlar ötüyor. Gökyüzü\nen güzel tonunu kuşanmış. Doğa bir ses yükseltmek\nistiyor. Âdeta bir çığlık… Bir yardım çağrısı… Kuşlar\nkonuşacak, ağaçlar da… İnsanlar; o sesi duysunlar,\nkonuşulanlara kulak versinler diye davet edilmişler.\nBu toprakların yetiştirdiği, uluslararası çapta en yetenekli müzik insanlarından olan Fazıl Say; piyanosunun\nbaşında hiç olmadığı kadar mutlu. Anlamlı bir günün\nmerkezinde çok duyarlı bir kitlenin karşısında. Piyanosunun tuşlarıyla doğaya tercümanlık edecek:\n- - - - diyecek her notasında.","stem":"Bu parçada boş bırakılan yere anlam akışına göre\naşağıdakilerden hangisi getirilmelidir?","options":["Doğanın dengesini bozmayın; ormanlar da canlıdır,\nonların canını yakmayın.","Doğanın sanata katkısı inkâr edilemez, edene de\nsanatçı denemez.","Bireysel yararın ne önemi var, asıl mühim olan toplumsal fayda.","Doğadan uzaklaştık, binalarla bezenmiş şehirlerde\nkendi derdimize daldık."],"answer":"A","solution":"Doğru cevap A seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Konu bulma","difficulty":"Orta","outcome":"Konu bulma","text":"","stem":"I. Metin\nKaranlık çökünce gecelere sığın\nSessiz yollarda tek başına dolaş\nMırıldandığın şarkılarla coş\nHerkesten, her şeyden uzak\nII. Metin\n— Gökyüzünü bahçeden de görebilirsin, neden illa bu\ntavan arası? Çıkmayacak mısın artık?\n— Çıkmak isteyen kim?\n— Yüzüne bir yabancı gibi mi bakalım?\n— Hayır!\n— Amacın bizi kendinden uzaklaştırmak mı?\n— Değil!\n— Ya ne?\n— - - - - !\nII. metindeki konuşma aşağıdakilerden hangisiyle\ntamamlanırsa I. metnin konusu yansıtılmış olur?","options":["Dikkat çekmek","Alacaklılardan kaçmak","Yalnız kalmak","Serin yer bulmak"],"answer":"C","solution":"Doğru cevap C seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"(I) 10 TL’nin arka yüzünde resmi bulunan kişiyi anımsadınız mı? (II) Adı Cahit Arf, bir bilim insanı, 1910-1997\nyılları arasında yaşamış dünya çapında ünlü bir\nmatematikçi ve fizikçidir. (III) Daha ilkokuldayken geometrideki “eşek teorimi” de denen Pisagor teorisini\nispat etmiştir. (IV) Daha sonraki yıllarda dünya matematik literatürüne kendi adı verilen “Arf teoremi” ile\ngirmiştir. (V) Bu teorideki üçgen, sözü edilen hayvanın\nkulaklarına benzediği için bu isim verilmiştir.","stem":"Bu parçada anlam bütünlüğünün sağlanması için\nnumaralanmış cümlelerden hangileri yer değiştirmelidir?","options":["I ve II","II ve III","III ve IV","IV ve V"],"answer":"D","solution":"Doğru cevap D seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"I. Mesela bulunduğumuz odada ısınan hava yukarı\ndoğru hareket eder.\nII. Bu hava hareketi ısının konveksiyonla yayılmasına\nbir örnektir.\nIII. Isı akışı sıcaktan soğuğa doğru gerçekleşir.\nIV. Bu yüzden pencereyi açtığımızda üst kısımdan\ndışarı doğru sıcak hava çıkışı olur.\nV. Yani pencereyi açtığımızda sadece soğuk hava\niçeri girmez, sıcak hava da dışarı çıkar.\nVI. Dışarıdaki soğuk hava da alt kısımdan içeri girer.","stem":"Numaralanmış cümlelerle anlamlı bir paragraf\noluşturulmak istendiğinde sıralama aşağıdakilerden hangisi olur?","options":["III - V - IV - VI - I - II","III - I - IV - VI - V - II","V - I - IV - VI - III - II","III - II - I - V - VI - IV"],"answer":"B","solution":"Doğru cevap B seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"Önceden sokakta oyunlar oynarken haksızlığı kabul\netmeyen, alaya fırsat vermeyen ve hakkına sahip çıkan, mahallesini önemseyen ve mahallesine değer\nveren, mahallesinin birlik ve beraberliğine azami özen\ngösteren bir toplumduk. - - - - Şimdi ailesi, komşusu göç yollarına düşüp parçalanıp yok olmakla karşı\nkarşıya kaldığında onların acısı karşısında suskun kalabilen, her türlü kötü ve zor koşullara rağmen yıllarca\nverdiği mücadele ile sahip olduğu varlıkları, değerleri\nkoruyamaz duruma gelen bir toplum olduk.","stem":"Bu metinde boş bırakılan yere mantık akışına göre\naşağıdakilerden hangisi getirilemez?","options":["Dayanışma duygusuna sahiptik.","Duyarlı ve merhametli birer insandık.","Cömert hatta savurgan bir toplumduk.","Birbirimizi kollar, gözetirdik."],"answer":"C","solution":"Doğru cevap C seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"I. “Her şeye karşı çıkarsın zaten!” demeyin.\nII. Başlatanları tebrik ederim ama tutacağını\nhiç sanmıyorum.\nIII. Yapılmadan yaptırılan bir uygulamanın\nbaşarıya ulaştığını nerede gördünüz?\nIV. Önce açıklayayım: “Sigara içmeyin!”\ndiyenler, kendileri sigara içiyorlar.\nV. “Sigaraya hayır!” kampanyası başladı.","stem":"Numaralanmış cümlelerle anlamlı bir metin oluşturulduğunda hangisi sondan ikinci sırada yer alır?","options":["I","II","III","IV"],"answer":"D","solution":"Doğru cevap D seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"I. Ev sahibi, ona neden bu kadar çok yediğini sormuş.\nII. Bu sözler üzerine ev sahibi “Yemek başkasınındır\nama karın senindir.” demiş.\nIII. Ev sahibinin karısı misafirleri uğurlamakla meşgulmüş.\nIV. Adam “Yemek başkasınındı da ondan.” diye cevap\nvermiş.\nV. Açgözlü bir adam bir gün misafirlikte o kadar çok\nyemiş ki karnı ağrımaya başlamış.","stem":"Numaralanmış cümlelerle anlamlı bir metin oluşturulduuğunda hangisi dışarıda kalır?","options":["I","II","III","IV"],"answer":"C","solution":"Doğru cevap C seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"Mizahı seven çocuklar açık fikirli olur, “mizah duygusu”na sahip bireyler ise hayatın zorlukları karşısında\ndaha dayanıklıdır. Mizahın Türkçe karşılığı “gülmece”dir ama mizah sadece gülmece değildir. Mizah\niçin güldürmek önemlidir ancak - - - - Mizahı seven;\ngülmeyi, eleştirmeyi, soru sormayı, öğrenmeyi seven\nçocuklardan iyi büyükler ortaya çıkar. O yüzden mizah\niçerikli kitaplardan uzak durmayın derim.","stem":"Bu metinde boş bırakılan yere anlam akışına göre\naşağıdakilerden hangisi getirilmelidir?","options":["düşündürme ve eleştirme özellikleri de ondan çok\naşağı değildir.","gerçekleri yanılmadan görebilme yeteneği de çok\nönemlidir.","mizahta ağırbaşlılık ve ciddiyetin de yeri bir başkadır.","yeri geldiğinde duygulandırma da olmazsa olmazlarındandır."],"answer":"A","solution":"Doğru cevap A seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"Birkaç gün önce yolda çok sevdiğim bir arkadaşımı\ngördüm. Durup kendisinin ve ailesinin nasıl olduğunu\nsordum. Bana baktı, alçak bir sesle şöyle dedi: “- - -\n- ” Hemen ardından tesadüfen bir başka arkadaşıma\ndaha rastladım. Ona da nasıl olduğunu sorduğumda\naynı ses tonuyla “- - - - ” dedi. Bu işlerin hangisine\nyetişeceğini şaşırmış. Sinirli, yorgun hatta bitkinlerdi.\nVe bu durumda olan sadece yetişkinler değil. On yıl\nönce büyük şehre taşındığımızda çok heyecanlıydık.\nGüzel bir mahalle ve okul bulduk. Her şey harikaydı.\nTaşındıktan sonra oldukça cana yakın komşularımızdan birine gidip onların kızıyla bizim kızımızın birlikte\noynayıp oynayamayacağını sorduk. Çok tatlı bir insan\nolan anne, telefonunu eline aldı ve takvimine baktı.\nBaktı, baktı… Nihayet bize dönüp “- - - -” dedi. Kendi\nkendime sordum: Nasıl bu hâle geldik biz? Bunu kendimize neden yapıyoruz? Bunu çocuklarımıza neden\nyapıyoruz? Çocukların çamur ve kir içinde kaldığı, etrafı dağıtarak eğlendiği, sıkıldığı dünyaya ne oldu?","stem":"Bu metinde boş bırakılan yerlerden herhangi birine\nmantık akışına göre aşağıdakilerden hangisi getirilemez?","options":["İkindiye kadar yoğun ders programı var, ikindiden\nsonra arkadaşlarının tiyatro gösterisine katılacak.","İki hafta sonra 45 dakikalık bir boşluğu var; kalan\nzamanı jimnastik, piyano ve şan dersleriyle dolu.","Başımı kaşıyacak vaktim bile yok ne yazık ki.","Çok meşgulüm… Yapmam gereken o kadar çok\nşey var ki!"],"answer":"A","solution":"Doğru cevap A seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Metinde yapı","difficulty":"Orta","outcome":"Metinde yapı","text":"I. Yine Antikacı Asaf amcanın dükkânına uğradık.\nAsaf amca bize çini bir vazo gösterdi.\nII. Bizim evde annem tam bir antika meraklısıdır.\nBugün onunla çarşıya çıkmıştık.\nIII. “Bu, bu olağanüstü!” dedi. Acaba benim görmediğim ne görüyor bu vazoda diye düşünerek vazoyu\nalıp ben de dikkatle incelemeye başladım.\nIV. Saraydan bilmem kimden kalmaymış! Annem,\ndünyanın sekizinci harikasına bakar gibi vazoyu\nhayranlıkla inceledi.\nV. O vakit Asaf amca “Aman kırılmasın!” diyerek\nvazoyu elimden aldı.","stem":"Numaralanmış bölümler olayların oluş sırasına göre aşağıdakilerin hangisinde doğru sıralanmıştır?","options":["I - III - IV - II - V","I - IV - II - V - III","II - I - IV - III - V","II - III - I - IV - V"],"answer":"C","solution":"Doğru cevap C seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"Son zamanlarda en çok konuşulan konuların başında\nküresel ısınma geliyor. Bu konuyla ilgili anlatılanlardan\nbazıları herkesi ürkütüyor. Çünkü yaşadığımız bu güzel dünyanın yaşanmaz hâle gelmesini görmek hatta\nhayal etmek bile istemiyoruz. Peki, anlatılanların hepsi doğru mu? Gerçekten bizi veya sonraki kuşağı zor\ngünler mi bekliyor? Hayvanlar, bitkiler ve dünyadaki\ngüzelliklerin varlığı tehlikede mi? Bunun gibi birçok\nsoruyu art arda sıralayabiliriz. - - - - Dünyanın güzelliğini kavrayıp bu güzelliği korumak için birey olarak\nüzerimize düşenleri yerine getirdiğimizde bir şeyler\ndeğişebilir.","stem":"Bu metinde boş bırakılan yere anlam akışına göre\naşağıdakilerden hangisi getirilmelidir?","options":["Ama en önemli başlangıç, elimizde olanların değerini anlamaktan geçiyor.","Küresel ısınmaya “Dur!” diyebilmemiz için ümidimizi asla yitirmemeliyiz.","Ancak öncelikle insan ırkının devamını sağlamanın\nyollarını araştırmalıyız.","Torunlarımıza güzel bir dünya bırakmak doğayı korumamıza bağlıdır."],"answer":"A","solution":"Doğru cevap A seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Metinde yapı","difficulty":"Orta","outcome":"Metinde yapı","text":"I. O an durdu ve yanındakilere seslendi:\nII. Mustafa Kemal, bir sabah savaş alanını geziyordu.\nIII. Bir ulusu, orduyu temsil ettiğinden yerde kalması\nuygun değildir.\nIV. Yerde parçalanmış bir bayrak, bir düşman bayrağı\ngördü.\nV. Bu bayrağı yerden kaldırınız!","stem":"Numaralanmış cümleler olayların oluş sırasına göre aşağıdakilerin hangisinde doğru sıralanmıştır?","options":["I - III - IV - II - V","I - IV - III - V - II","II - I - IV - III - V","II - IV - I - V - III"],"answer":"D","solution":"Doğru cevap D seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"“- - - -” sözü bazı durumlarda gerçek olabilir. Fırtınaların oluşması için gerekli olan nemli ve sıcak hava\natmosferde yükselirken soğur ve içindeki su yoğunlaşmaya başlar. Hava tekrar aşağı doğru hareket ederken\nısınır ve nemini kaybeder. Bu durum, fırtına bulutlarının\naltındaki havanın sakin ve durgun olmasına yol açar.","stem":"Bu metindeki boşluğa aşağıdakilerden hangisi getirilmelidir?","options":["Rüzgâr ekip fırtına biçmek","Fırtına öncesi sessizlik","Bir bardak suda fırtına koparmak","Fırtına patlamak"],"answer":"B","solution":"Doğru cevap B seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"(I) Amerikan Havacılık ve Uzay Dairesine (NASA) ait\nDawn adlı uzay aracı, yaklaşık bir yıldır Ceres’in yörüngesinde dolanarak cüce gezegen hakkında bilgi\ntopluyor. (II) Bu süreçte elde edilen fotoğraflarda cüce gezegenin yüzeyinde parlak beyaz alanlar olduğu\ngörüldü. (III) Aynı alanlarda daha önce de su buharına\nrastlanmıştı. (IV) Yapılan incelemelerde parlak alanların büyük bir olasılıkla tuzlu su buzunun gaz hâle\ngeçmesi sonucunda geride kalan magnezyum sülfat\nyığınları olduğu sonucuna ulaşıldı. (V) Araştırmacılar\ncüce gezegenin yüzeyinin altında tuzlu su buzu tabakası bulunduğunu ve bu tabakanın bir asteroidin\nçarpmasıyla ortaya çıkmış olabileceğini düşünüyorlar.","stem":"Bu parçada numaralanmış cümlelerden hangisi\nparçanın anlam bütünlüğünü bozmaktadır?","options":["II","III","IV","V"],"answer":"B","solution":"Doğru cevap B seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"(I) Hata yapmayan insan yoktur çünkü hataya düşmek çoğu zaman elimizde değildir. (II) Ancak her an\nhata yapmaktan korkmak da doğru bir şey olmaz.\n(III) Bu durum, hevesimizi kırar; iş yapma gücümüzü\nyok eder. (IV) Günlük hayatta bizi zorlayacak pek çok\nolayla karşı karşıya geliriz. (V) O zaman hata yapmak\nda kaçınılmaz olur ve bundan dolayı talihi suçlamak\nda adaletli olmaz.","stem":"Bu parçada anlam bütünlüğünün sağlanması için\nkaç numaralı cümle metinden çıkarılmalıdır?","options":["II","III","IV","V"],"answer":"C","solution":"Doğru cevap C seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Metinde yapı","difficulty":"Orta","outcome":"Metinde yapı","text":"(I) Orhan Pamuk’un ilk romanı 1982 yılında yayımlandı.\n(II) Yazarın “Sessiz Ev” adlı romanının Fransızca çevirisi 1991 senesinde “Prix de la decouverte Europene”\nödülünü aldı. (III) Orhan Pamuk, 22 yaşına kadar sürekli\nresim yaptığından, ressam olacağını düşünüyordu. (IV)\nİstanbul Teknik Üniversitesinde üç yıl mimarlık okuduktan sonra mimar ve ressam olmayacağına karar\nverdi. (V) Mimarlık bölümünü bırakan Pamuk, İstanbul\nÜniversitesinde Gazetecilik okudu. (VI) 23 yaşından\nsonra yazar olmaya karar verdi ve tüm uğraşlarını bir\nkenara koyup eve kapanıp kendini yazmaya adadı.","stem":"Bu parça iki paragrafa ayrıldığında ikinci paragraf\nkaç numaralı cümleyle başlar?","options":["II","III","IV","V"],"answer":"B","solution":"Doğru cevap B seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"(I) Yapılan araştırmalara göre doğada yürümek pek\nçok sağlık sorununa yakalanma riskini azaltıyor. (II) Engebeli arazilerde, patikalarda ya da ormanlık alanlarda\nyürümenin hem zihin hem de beden sağlığımız için\noldukça yararlı olduğu görüşünde olan birçok uzman\nvar. (III) Çünkü doğa yürüyüşü yaparken yalnızca tepelere çıkmakla kalmayıp çoğunlukla günlük yaşamda\nkullanılandan daha ağır olan yürüyüş botlarını tercih\nettiğimizden dengemizi sağlamak için daha fazla kas\nçalıştırırız. (IV) Böylece düz zeminde yürüdüğümüzden\nçok daha fazla enerji harcarız.","stem":"Bu metinde numaralanmış cümlelerin hangisinden\nsonra “Hatta kimi zaman fiziksel ve zihinsel olarak iyileşmeyi bile sağlıyor.” cümlesi getirilirse metindeki\ndüşüncenin akışı bozulmaz?","options":["I","II","III","IV"],"answer":"A","solution":"Doğru cevap A seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Metinde yapı","difficulty":"Orta","outcome":"Metinde yapı","text":"","stem":"(I) İyi konuşabilmenin en önemli şartı geniş bir kültür\nbirikimine sahip olmaktır. (II) Engin bir dünya görüşünden ve kültürden yoksun olanlar buna paralel olarak\ndüzgün konuşamazlar. (III) Onların konuşmaları can\nsıkıcı olmaktan öteye gidemez. (IV) Kültür bir birikim\nişidir. (V) İnsan bu birikimi çok gezmekle, okumakla,\nhobi edinmekle elde edebilir.\nBu metin iki paragrafa ayrılmak istenirse numaralanmış cümlelerden hangisi ilk paragrafın son\ncümlesi olur?","options":["I","II","III","IV"],"answer":"C","solution":"Doğru cevap C seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"(I) Buz tırmanışı yapan sporcular; su geçirmeyen, sıcak\ntutan giysiler giyer ve özel araç gereçler kullanır. (II) Bu\ngiysiler ve araç gereçler çok hafif malzemelerden yapılır. (III) Buz çekici ve buz kazması, buz tırmanışı yapan\nsporcuların olmazsa olmazlarındandır. (IV) Çekicin ve\nkazmanın sivri ve tırtıklı uçlarını buza saplayıp kendilerini yukarıya doğru çekerler. (V) Sporcular tırmanırken\nbir ellerinde buz çekicini, diğer ellerindeyse buz kazmasını tutar.","stem":"Bu parçada anlam bütünlüğünün sağlanabilmesi\niçin numaralanmış cümlelerden hangileri birbiriyle\nyer değiştirmelidir?","options":["I ile III","II ile III","II ile IV","IV ile V"],"answer":"D","solution":"Doğru cevap D seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"Bir kişinin kendi yaşamını nesnel bir bakış açısıyla yazdığı metin türüne otobiyografi denir. Aşağıda Kemal Sunal’ın\notobiyografisinden bir kesit verilmiştir\n(I) 1944 tarihinde İstanbul’un Küçükpazar\nsemtinde Malatyalı bir ailenin ilk çocuğu\nolarak dünyaya gelmişim.\n(II) Liseyi 11 yılda tamamladım ama bu\nbenim tembelliğimden ileri gelen bir şey\ndeğildi. 15-20 kişilik bir grubumuz vardı.\nTüm zamanımızı beraber geçiriyordu. Bir\nnevi haylazlıktı tabii. Yaz tatillerinde okul\nmasraflarına yardımcı olmak için çalışırdım.\n(III) Askere gittiğimde diğer askerlerin beni\ngörünce gülmesi sonucu birliğin düzenini\nbozduğum gerekçesi ile Armoni Mızıkası\nisimli moral grubuna geri hizmete verildim.\n(IV) Vefa Lisesinde\nson sınıf öğrencisiyken oynadığım\namatör oyundan sonra, nasıl oldu\nbilmem, kendimi sahici bir sahnede buldum. Ses Tiyatrosundaki\nilk rolüm çok kısaydı ama seyirci\nkahkahadan kırılmıştı. Bu da benim hoşuma gitmişti. Bildiğiniz\ngibi o gün bugündür insanları\ngüldürmeyi seviyorum.","stem":"Bu parçada anlam akışındaki bozukluğun giderilmesi için numaralanmış bölümlerden hangileri yer değiştirmelidir?","options":["I ve III","II ve III","II ve IV","III ve IV"],"answer":"D","solution":"Doğru cevap D seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"(I) Askerî iletiler, banka hesaplarının ve elektronik\npostaların şifreleri gibi pek çok bilginin gizliliğinin sağlanması ve korunması gerekir. (II) İkinci Dünya Savaşı\nzamanında gizli bilgiler şifrelenerek telsizle gönderilirmiş. (III) Bu bilgileri şifrelemek ve sonra bu şifreleri\nçözmek için kullanılan gelişmiş yöntemler ve uygulamalar var. (IV) Bu yöntem ve uygulamalarla ilgilenen\nbilim dalına kriptoloji ya da şifre bilimi deniyor. (V) Şifre\nbilimi tekniğiyle şifrelenmiş şifreleri çözmenin çok zor\nhatta bazen imkânsız olduğu bile söyleniyor!","stem":"Bu parçada numaralanmış cümlelerden hangisi\nparçanın anlam bütünlüğünü bozmaktadır?","options":["II","III","IV","V"],"answer":"A","solution":"Doğru cevap A seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Metinde yapı","difficulty":"Orta","outcome":"Metinde yapı","text":"(I) Bedenimizde yaşamını sürdüren birçok bakteri\nbulunur. (II) Tenimizde, bağırsaklarımızda ve ağız boşluğumuzda bulunan “iyi” bakteriler, bedenimizin doğal\nişleyişine katkıda bulunur. (III) Kan; vücutta oksijen,\nbesin maddeleri, vitaminleri ve antikorları dokulara taşıyan yaşamsal bir sıvıdır. (IV) Eğer “kötü” bakteriler\nkana girerse, bedenimizin bağışıklık sistemi bu “kötü” bakterilerle savaşarak onları yok etmeye çalışır.\n(V) Bağışıklık sistemimiz savaşamayacak durumda ise\nyardımcı olmak için antibiyotik özellikte ilaçlar kullanmak gerekir.","stem":"Bu parça iki paragrafa ayrıldığında ikinci paragraf\nkaç numaralı cümleyle başlar?","options":["II","III","IV","V"],"answer":"B","solution":"Doğru cevap B seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"(I) Kaptaki suya deterjan ekleyip hızlıca karıştırdığımızda bol baloncuklu köpük elde ederiz. (II) Tundra\nkurbağaları da benzer biçimde köpükten yuvalar hazırlayarak yavrularını dış etkilerden koruyabiliyormuş.\n(III) Bu kurbağalar, ürettikleri deterjan benzeri kimyasalı\nsuya bırakıp ayaklarıyla karıştırarak suyun köpürmesini\nsağlıyormuş. (IV) Bu kurbağaların yaptıkları köpükten\nyuvalar, yavrular büyüyüp köpükten ayrıldıktan sonra\nbile günlerce bozulmadan kalabilir.","stem":"Bu parçada numaralanmış cümlelerin hangisinden\nsonra “Böylece yüzebilen güvenli bebek bakım yuvaları hazır hâle geliyormuş.” cümlesi getirilirse metnin\nanlam bütünlüğü sağlanmış olur?","options":["I","II","III","IV"],"answer":"C","solution":"Doğru cevap C seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Metinde yapı","difficulty":"Orta","outcome":"Metinde yapı","text":"(I) Soyuz kapsülü; yörünge modülü, iniş modülü ve\nservis modülü olmak üzere üç bölümden oluşur.\n(II) Soyuz kapsülünün en üstünde yer alan yörünge modülü Uluslararası Uzay İstasyonuna bağlanan\nmodüldür. (III) Ortada yer alan iniş modülüyse Soyuz\nkapsülünün dönüşte atmosfer tabakalarını geçerek\nyeryüzüne ulaşan tek parçasıdır. (IV) Astronotlar, uzaydaki görevlerini tamamladıklarında dönüş yolculuğu\niçin hem istasyonda hem de Rusya’da bulunan görev\nkontrol merkezinde hazırlıklar başlar. (V) Kapsüller Orta\nAsya’da, Kazakistan’ın geniş düzlüklerine iniş yapar.","stem":"Bu parça iki paragrafa ayrıldığında ikinci paragraf\nkaç numaralı cümleyle başlar?","options":["II","III","IV","V"],"answer":"C","solution":"Doğru cevap C seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Dil ve anlatım","difficulty":"Orta","outcome":"Dil ve anlatım","text":"","stem":"Aşağıdaki metinlerin hangisinde kullanılan düşünceyi geliştirme yolu, yay ayraç içinde yanlış verilmiştir?","options":["Ulaşımda toplu taşımadan yana olsak da taksiler yaşamımızın bir parçası oldu. Özellikle kentlerde bir yere çabucak\nulaşmak için taksiye biniliyor. Taksi dendiğinde aklımıza ilk sarı otomobiller gelse de ülkemizde deniz taksi, hava\ntaksi ve fayton gibi farklı taksi çeşitleri de var. (Tanımlama)","Bulunduğunuz bölgede hangi canlıların yaşadığını birtakım ipuçlarından yararlanarak öğrenebilirsiniz. Gölet kıyısında iseniz çamurda gördüğünüz perdeli ayak izleri yaban ördekleri veya kazlara ait olabilir. Öte yandan çamurun\nüzerindeki iz dört ya da beş parmaklı bir patiye benziyorsa bu iz memeli bir hayvana aittir. (Örneklendirme)","İlk aynalar MÖ 6000’li yıllarda Anadolu’da yapılmış. Ancak bunlar günümüzde kullanılan aynalara pek benzemiyormuş. Çünkü bu aynalar volkanik bir taş olan obsidyenin yüzeyinin düzleştirilip cilalanmasıyla yapılıyormuş. Daha\nsonra insanlar bakır, gümüş, altın gibi metallerin yüzeylerini parlatarak ayna yapmaya başlamışlar. (Karşılaştırma)","Çin’de üretilen ve sadece bir yolcu taşıyabilen insansız hava aracı elektrikle çalışıyor. Dört saatte şarj edilebilen araç,\n300 ila 500 metre yükseklikte ve saatte 100 kilometre hızla uçabiliyor. 23 dakika havada kalan bu araç, 100 kilogram\nyük taşıyabiliyor. (Sayısal verilerden yararlanma)"],"answer":"A","solution":"Doğru cevap A seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Dil ve anlatım","difficulty":"Orta","outcome":"Dil ve anlatım","text":"O zamanlar altı yaşlarında var ya da yoktum. Sabahın ilk ışıklarıyla çıktığımız tatil yolculuğu sırasında ormanlık\nbir alanda durmak zorunda kalmıştık. Annem ve babam küçük kardeşimle ilgileniyordu. Ben de arabadan inmiş\normanı seyrediyordum ki orman içinden bir köpek çıktı. Bana yalvarır gözlerle bakıyor, sanki onu takip etmemi\nistiyordu. Arkasından yürüdüm. Beni üç yavru köpeğin bulunduğu bir yuvaya götürdü. O kadar savunmasız ve\naç görünüyorlardı ki hemen annem ve babamın yanında gittim. Köpeklerden bahsettim, annemin hazırladığı\nyiyeceklerden ve sudan köpeklere götürdük. Karınlarını doyurup da teşekkür edercesine bizi yalamaları hepimizi hem hüzünlendirmiş hem de mutlu etmişti. Köpeklerle vedalaşıp tekrar yola çıktığımızda güneş neredeyse\ntepeye ulaşmıştı.","stem":"Bu metinde aşağıdakilerin hangisinden daha çok yararlanılmıştır?","options":["Bir olayı zaman akışı içerisinde aktarmadan","Herhangi bir konu hakkında okuyucuyu bilgilendirmeden","Varlıkların ayırt edici özelliklerini okuyucu gözünde canlandırmadan","Ortaya atılan bir düşünceyi savunmadan"],"answer":"A","solution":"Doğru cevap A seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Dil ve anlatım","difficulty":"Orta","outcome":"Dil ve anlatım","text":"El işçiliği, ürünlerin bizzat insan elinden çıkmasıdır. Bir\nkişi bir ürünü başından sonuna kadar tek başına üretir. Bu, çok uzun ve zahmetli bir süreçtir. Bu nedenle\nürünün hem maliyeti hem de satış fiyatı yüksek olur.\nAyrıca el işçiliğiyle üretilen hiçbir ürün birbirinin tıpatıp\naynısı olmadığından parçaların değişimi de pek mümkün olmaz. Bu da ürünün bir parçasının bozulması ya\nda kırılması durumunda ürünün kullanılamaz hâle gelmesine neden olur.","stem":"Bu parçada aşağıdakilerden hangisi kullanılmıştır?","options":["Betimleme","Açıklama","Tartışma","Tanık gösterme"],"answer":"B","solution":"Doğru cevap B seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Dil ve anlatım","difficulty":"Orta","outcome":"Dil ve anlatım","text":"İnsanoğlu hep büyük şeylere önem verir. Ancak büyük\nşeylere ulaşabilmek için küçük şeylere ihtiyacımız vardır. Küçük şeylerin önemi ise geleneksel kültürümüzde\n“Bir mıh bir nal kurtarır, bir nal bir at kurtarır.” atasözüyle ifade edilir. Eskiden de insanlar küçük belirtilerin\nbüyük etkileri olduğuna inanırmış. Hintliler, küçük yağmur kümelerinden muson yağmurların geldiğini tahmin\nedermiş. Anadolu köylüsü de bir zamanlar bir taraftan\nyaklaşan bulut kümelerinden sağanağın geldiğini anlayıp tarlasından harmanı kaldırırmış.","stem":"Bu metinde düşünceyi geliştirme yollarından hangisine başvurulmuştur?","options":["Örnekleme - Tanımlama","Benzetme - Tanık gösterme","Örnekleme - Karşılaştırma","Karşılaştırma - Benzetme"],"answer":"C","solution":"Doğru cevap C seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Dil ve anlatım","difficulty":"Orta","outcome":"Dil ve anlatım","text":"","stem":"Tanımlama: Bir nesne ya da varlığın özelliklerinin eksiksiz olarak belirtilmesidir.\nKarşılaştırma: Aralarında ilişki bulunan varlık ya da kavramların benzer veya farklı yönleriyle kıyaslanmasıdır.\nBenzetme: Bir kavramı ya da varlığı başka bir kavram ya da varlığın özellikleriyle anlatılmasıdır.\nBu düşünceyi geliştirme yollarının tamamı aşağıdaki metinlerin hangisinde kullanılmıştır?","options":["Dünya’nın, Güneş’in çevresinde dolaştığı 365 gün 6 saatlik süreye bir yıl denir. Tarih boyunca Dünya’nın Güneş\nçevresinde ya da Ay’ın Dünya çevresinde dolanma sürelerini temel alan pek çok takvim kullanıldı. Ancak bunlardan\nbirkaçı dışında çoğu arapsaçı gibi karmakarışık ve yanlıştı.","MÖ 46 yılında Roma İmparatoru Julius Ceasar (Jül Sezar) kendini dönemine kadar kullanılan takvimleri basitleştirmek için kendi adına verdiği “Jülyen takvim”ni icat etti. Bu takvime göre bir yıl 365 gün 6 saat kabul ediliyor ve her\nyıl artan altı saat dört yılın sonunda toplam bir gün ederek şubata eklenir. Böylece şubatın 29 çektiği yıllara artık yıl\ndenir.","Gregoryen’in, Julius Ceasar gibi kendi ismini verdiği takvimde dört yılda bir artan altışar saat toplanır ve bir gün\neder. Bu bir gün yine şubata ekleniyor. Ancak Gregoryen takvimde artık yılların hesaplanması biraz farklıdır. Şubat\nayı Gregoryen takvimde, Jülyen takvimdeki gibi her dört yılda bir 29 çekmez.","Miladi takvim, Güneş yılını esas alan bir takvimdir. Dünya’da en yaygın olarak kullanılan takvimlerdendir. Bu takvime\ngöre 1 yıl 365 gün 6 saatten oluşmaktadır. Hata oranı da en az olan takvimdir."],"answer":"A","solution":"Doğru cevap A seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"","stem":"Güney Amerika’nın birçok yeri eskiden çeşitli ulusların sömürgesiydi. Şimdilerde bu durum sona ermiş olsa da insan,\ngezi sırasında geçmişle bugünü birlikte yaşama olanağı buluyor. Özellikle amazon çevresinde durum böyle ama yaylalarda yaşayan Kızılderililer, dün olduğu gibi bugün de yaşamlarını doğalarına uygun ortamlarda sürdürüyorlar.\nBu parçaya,\nÜç bin beş yüz metre yükseklikteki bir dağın doruğuna kurulmuş olan Machu Picchu (Maçu Pikçu), gerçek Kızılderililerin\nolduğu Cuzco kentidir. Machu Picchu; dünyaca ünlü İnka medeniyetine beşiklik etmiş görkemli, şaşırtıcı, düşündürücü\nve yer yer ürkütücü bir kenttir.\nmetni eklendiğinde parçanın anlatımıyla ilgili aşağıdakilerden hangisi söylenebilir?","options":["Bir durum benzetme yoluyla somutlaştırılır.","İnsan dışı bir varlığa insana ait özellik aktarılır.","Bahsi geçen konuda örneklendirme yapılır.","Anlatıma nesnel bir boyut kazandırılır."],"answer":"C","solution":"Doğru cevap C seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"Erdemin, bereketin doldurur haneleri\nSensiz hayat toprağa bile yük olur\nŞemsiyesi altında yürürsün bulutların\nİçine karışırsın en güzel rüzgârların\nBiraz sonra evlerin ışıkları yanacak\nKaranlık bir köşede durup dikileceğim\nPencereden bakanlar beni heykel sanacak\n‘’Acaba heykel miyim?’’ diye irkileceğim\nElbette güzel günlerimiz olacak, elâ gözlüm\nBir taze ekmek gibi sıcak\nBereketli gece yağmurlardan sonra güneş\nBir elmas iğne gibi parlayacak\nPuslu aydınlıkta bir bahar günü\nGece, bir tepeden seyrettik, büyük\nYıldızların suda döküldüğünü\nÜlker, Demirboğa, Altınkelepçe","stem":"Bu şiirlerde aşağıdakilerden hangisine yer verilmemiştir?","options":["Tanımlama","Benzetme","Örnekleme","Karşılaştırma"],"answer":"A","solution":"Doğru cevap A seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Dil ve anlatım","difficulty":"Orta","outcome":"Dil ve anlatım","text":"İnsan betimlemeleri, iç betimleme (ruhsal tasvir) ve dış betimleme (fiziksel tasvir) olmak üzere ikiye ayrılır.\n• İç (ruhsal) betimleme: İnsanların gözle görülmeyen; sevecenlik, sevimlilik, çalışkanlık, karamsarlık, fesatlık, iyi kalplilik, kıskançlık gibi özelliklerinin anlatılmasına iç (ruhsal) betimleme denir.\n• Dış (fiziksel) betimleme: Kişilerin gözle görülen; boyu, kilosu, kıyafeti, ayakkabıları gibi özelliklerinin ayrıntılı olarak\nanlatılmasına dış tasvir denir.","stem":"Buna göre aşağıdakilerin hangisinde iki betimleme bir arada kullanılmıştır?","options":["Önümde yürüyen uzun boylu, geniş omuzlu ve gür saçları olan orta yaşlı bir adamdı. Hızlı adımlarla yolun hemen\nsolundaki patika yoldan tepedeki evine tırmanmaya başladı. Uzun bacakları sayesinde evine daha kolay varacağı\nbelliydi. Nedense birden geriye dönüp geldiği yolu koşmaya başladı. Arkasından bakakaldım.","Anneannemin evin içinde her zaman oturduğu bir köşesi vardı. Oraya oturur uzun siyah saçlarını tahtadan yapılmış\ntarağıyla güzelce tarar sonra da bir güzel örerdi. Örgüsü bitince başına beyaz yazmasını örterdi. Görünüşü sert ama\nyüreği yufka bir kadındı anneannem. Yanına her gittiğimizde cebimize koyacak bir şeyleri her zaman olurdu.","Her akşam aynı saatlerde pencereye çıkıp etrafı seyre dalan bu adamın bakışlarındaki hüzünle karışık karamsar bakışları beni de efkârlandırırdı. Ne derdi vardı, bilmem ama onu görmek benim de içimde tufanlar yaratırdı. Kendime\ngelmek için gidip çocuklarıma sarılırdım.","Okulumuzun emekliliği yaklaşmış memuru Ahmet Bey, her zaman aynı saatte okulda olurdu. Annesiyle yaşayan bu\nkısa boylu, hafif kilolu, yaşlı adamın sizi gördüğünde her zaman anlatacak bir şeyleri olurdu. Geniş ağızın içindeki\ninci gibi dizilmiş beyaz dişleri konuşurken ortaya çıkar ve ne kadar bakımlı olduğunu belli ederdi."],"answer":"B","solution":"Doğru cevap B seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Dil ve anlatım","difficulty":"Orta","outcome":"Dil ve anlatım","text":"Yunus Emre’nin geniş halk kitlelerince sevilmesinin ilk sebebi, hiç şüphesiz tüm insanlığı kucaklayan sevgisidir. İkinci\nsebep ise kullandığı yalın, derin ve içten Türkçesidir. Onun Türkçesi sular kadar serin, deryalar kadar derin, ovalar kadar\nengin, krallar kadar zengindir. Dağlar kadar ulu, ormanlar kadar sulu, bulutlar kadar dolu, muhabbettir her daim yolu…\nOnun şiirleri bir şelale gibidir; okuyana serinlik, dinleyene derinlik, anlayana güzellik, yaşayana velilik ikram eder: Taştın\nyine deli gönül / Sular gibi çağlar mısın / Aktın yine kanlı yaşım / Yollarımı bağlar mısın?","stem":"Bu metnin anlatımında aşağıdakilerin hangisinden yararlanılmamıştır?","options":["Tanımlama","Benzetme","Karşılaştırma","Örneklendirme"],"answer":"A","solution":"Doğru cevap A seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Dil ve anlatım","difficulty":"Orta","outcome":"Dil ve anlatım","text":"Martılar çoğunlukla deniz ve göl kıyılarında yaşar.\nMartıların farklı türleri farklı özelliklere sahiptir. Özellikle boyları çok değişiklik gösterir. Küçük bir martının\nkanatlarının bir uçtan diğerine uzunluğu yaklaşık 70\nsantimetreyken büyük bir kara sırtlı martı uzunluğu\n170 santimetreye ulaşabilir. Martılar genellikle beyaz\nve gridir. Ancak bacakları, gagaları ve kanatlarının\nüzerindeki renkler türlere göre farklılık gösterir. Gümüş\nmartılar sarı renkli gaga ve bacaklarıyla diğer birçok\nmartıdan kolayca ayırt edilebilen büyük kuşlardır.","stem":"Bu metnin anlatımında aşağıdakilerin hangisinden\nyararlanılmamıştır?","options":["Bir varlığı başka bir varlığa ait özelliklerle anlatmaktan","Varlıkların farklılıklarını karşılaştırarak anlatmaktan","Varlıkların ayırt edici özelliklerini okuyucunun gözünde canlandırmaktan","Sayısal verilerle ortaya konan düşünceyi kanıtlamaktan"],"answer":"A","solution":"Doğru cevap A seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"","stem":"Başım köpük köpük bulut, içim dışım deniz\nBen bir ceviz ağacıyım Gülhane Parkı’nda\nBudak budak, şerham şerham ihtiyar bir ceviz\nNe sen bunun farkındasın ne polis farkında\nBu dizelerde aşağıdakilerin hangisine dair bir betimleme yapılmıştır?","options":["Deniz","Ceviz ağacı","Polis","Bulut"],"answer":"B","solution":"Doğru cevap B seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Dil ve anlatım","difficulty":"Orta","outcome":"Dil ve anlatım","text":"","stem":"Aşağıdaki metinlerin hangisinde bulunan anlatım biçimi ya da düşünceyi geliştirme yolu yay ayraç içinde yanlış\nverilmiştir?","options":["Nefes nefese tepeye ulaştı. Koşarak naylon ve çuvallarla sıkı sıkı örttüğü su kaplarının yanına vardı. Oturup biraz\nsoluklandı. Gece tütenler kokularını yaymaya başlamıştı bile. Derin derin havayı kokladı. En küçük bir esinti yoktu.\n(Öyküleme)","Dedemi defalarca rüyamda gördüm. Hep “Zeytinlerini gör!” diyordu bana. Gidip gördüm. Kocaman ağaç olmuştu.\nTek tek dolaştım, okşadım, gölgelerinde oturdum. Zeytin ağaçları üzerine konuşmalarını anımsadım. Onun için her\nağacın bir kimliği, kişiliği vardı. Birlikte yaşadığı hayvanlarının birer kimliği, kişiliği olduğu gibi! (Benzetme)","Beş çocuğun beşinin de Tanrı tarafından gönderildiğine inanan halk, içlerinden birini “hakan” yapmak istedi. Bögü\nHan hem en büyükleriydi hem de ötekilerden daha güzel, daha zeki ve daha yiğit görünüyordu. Bögü Han’ın hepsinden, her hususta üstün olduğunu anlayan halk onu hakan olarak seçti. (Karşılaştırma)","Atatürk, “Akıl ve mantığın çözemeyeceği sorun yoktur.” derdi. O, aklın rehberinin bilgi, bilim olduğunu benimsemişti.\nTarihte uygar olarak kalabilen uluslar, şüphe yok ki bilim hayatından payını almış bireylerin oluşturduğu topluluklardır.\nAtatürk, cumhurbaşkanı sıfatıyla “Hayatta en hakiki mürşit ilimdir.” sözünü söylemiştir. (Tartışma)"],"answer":"D","solution":"Doğru cevap D seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Dil ve anlatım","difficulty":"Orta","outcome":"Dil ve anlatım","text":"Yazdan kışa, kıştan yaza geçerken doğada birçok değişim olur. Bu değişimlerden biri de hayvanların renkleriyle ilgilidir.\nKutup bölgelerinde yaşayan, yazın koyu renk olan kutup tilkisi sonbaharda renk değiştirmeye başlar ve kışın beyaz olur.\nKürklü hayvanların kalın olan beyaz kış kürkleri onların ısınmalarına yardımcı olur. İlkbaharda kutup tilkisi tekrar renk\ndeğiştirmeye başlar ve yazın eski hâllerine döner. Bu renk değişimi bulundukları ortamda fark edilmemelerini de sağlar.\nBöylece hem avcı hayvanlar tarafından zor görülürler hem de kendilerini belli etmeden avlarına yaklaşabilirler.","stem":"Bu metinde kullanılan düşünceyi geliştirme yolu aşağıdakilerin hangisidir?","options":["Örnekleme","Benzetme","Tanık gösterme","Tanımlama"],"answer":"A","solution":"Doğru cevap A seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Dil ve anlatım","difficulty":"Orta","outcome":"Dil ve anlatım","text":"","stem":"Ağaçlar kalem olsa\nYaprağı kâğıt olsa\nYazılmaz benim derdim\nDeniz mürekkep olsa\nGökte yıldız az kaldı\nTeller koptu saz kaldı\nMaraz etme güzelim\nKavuşmamız az kaldı\nAy doğar sini gibi\nSalınır selvi gibi\nBütün Kıbrıs’ı gezdim\nBulamadım senin gibi\nBu manilerin dil ve anlatımlarıyla ilgili aşağıdakilerden hangisi ortaktır?","options":["Dize sonlarında aynı kelimeler tekrar etmiştir.","Abartma sanatından yararlanılmıştır.","Benzetmelerle anlatım somutlaştırılmıştır.","Sevdiğine duyulan özlemi konu almaktadır."],"answer":"A","solution":"Doğru cevap A seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Yardımcı düşünce","difficulty":"Orta","outcome":"Yardımcı düşünce","text":"Yunus Emre’yi anlatmak için ne kalem yeter ne de kelam! Zira uçsuz bucaksız deryayı hangi söz anlatabilir? Gürül gürül\nakan ırmağı hangi dize ifade edebilir? Yunus bir İpek Yolu çarsısıdır; her tüccar onda elbet kendine yaraşır bir şey bulur.\nHiçbir sözü zayi değildir. Yeter ki okuyan âlim gerek, dinleyen arif gerek!..","stem":"Bu metnin anlatımıyla ilgili aşağıdakilerden hangisi söylenemez?","options":["Bir durumun nedeni açıklanmıştır.","Yalın bir dil kullanılmıştır.","Öznel ifadelere yer verilmiştir.","Benzetmeden yararlanılmıştır."],"answer":"B","solution":"Doğru cevap B seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"","stem":"Geçtiğimiz yıl tatilde nereye gittiğinizi hatırlıyor musunuz? Okula başladığınız ilk gün beşinci sırada oturan kişinin adını?\nPeki, 23 Nisan 2018’de saat 13.00’te nerede, ne yaptığınızı? Geçmişte öğrendiğimiz bilgiler, duyu organlarımızla algıladıklarımız ya da bir durum karşısında hissettiklerimiz zihnimizde yer edinir.\nBu parçaya,\nBu yer edinme, kütüphane raflarına dizilmiş kitaplar gibidir. Bazı bilgiler hatırlanır, bazılarıysa kütüphanenin tozlu raflarında kaybolur yani unutulur.\nmetni eklendiğinde parçanın anlatımıyla ilgili aşağıdakilerden hangisi söylenebilir?","options":["Bir durum olduğundan fazla gösterilerek abartılmıştır.","Anlatılanlar benzetme yoluyla somutlaştırılmıştır.","Anlatıma nesnel bir boyut kazandırılmıştır.","Ortaya konan düşünce örneklenmiştir."],"answer":"B","solution":"Doğru cevap B seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Yardımcı düşünce","difficulty":"Orta","outcome":"Yardımcı düşünce","text":"","stem":"Dağlar düz, günler yüz, gençler kız, arı vız, kollar hız\nVurun, vurun değneklerinizi yüklü dallara be gençler\nDökülü dökülüversin semiz bal gibi harnuplarınız\nToplasın analarınız, bacılarınız, yavuklularınız\nHarnuplar çok ballı\nSilkele şu zorlu dalı\nBu dizelerle ilgili,\nI. Seslenme bildiren bir ifade kullanılmıştır.\nII. Karşılaştırmadan yararlanılmıştır.\nIII. Benzetme yapılmıştır.\nIV. Birinci kişi ağzından anlatılmıştır.\nyargılarından hangileri söylenemez?","options":["I ve II","I ve III","II ve IV","III ve IV"],"answer":"C","solution":"Doğru cevap C seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Yardımcı düşünce","difficulty":"Orta","outcome":"Yardımcı düşünce","text":"","stem":"Bir çiçek vardı\nBoyu aşınca bulutları\nKomşu olunca yıldızlarla\nKendini güneşe akraba sandı\nBaktı aşağılara\nBeslendiği topraktan utandı\nBu dizeler ile ilgili aşağıdakilerden hangisi söylenemez?","options":["Hayalî unsurlara yer verilmiştir.","Kişileştirmeden yararlanılmıştır.","Hikâye edici özellik taşımaktadır.","Benzetmelerle anlatım zenginleştirilmiştir."],"answer":"D","solution":"Doğru cevap D seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"• Örneklemeye başvurulmuştur.\n• Tanık göstermeden yararlanılmıştır.","stem":"Aşağıdaki metinlerin hangisinde bu özelliklerin tümüne yer verilmiştir?","options":["Devlet adamlarının kitap yazmaları dikkatinizi çekiyor mu? Alfred de Visny’in dediği gibi “Hükümdarlar, asıl gücün\nkitapta olduğunu gördükten sonra kitap yazmaya başladılar.” İlk insan ve ilk peygamber Hz. Adem’in on sayfalık bir\nkitapla vazifelendirilişi, insanların kitapsız idare edilemeyeceklerinin en açık delilidir.","Aristo dermiş ki: “Ey dostlarım, dünyada dost yoktur.” Aslında Aristo’ya hak vermemek zor. Büyük bilge görmüş\ngerçeği. Dost sandıklarının dost olmadığını.","Anadolu’nun konukseverliği gelenekseldir. Bu geleneğin halkalarından biridir kahve. Sizi bir acı kahve içmeye çağıran dostunuza neden “acı kahve” diyemezsiniz; bu acılıkta, yıllar yılı sürecek bir tatlılık, yakın bir dostluk vardır; bu\nyüzden Anadolu’da “Bir fincan kahvenin kırk yıl hatırı vardır.” sözü her zaman söylenir.","İşlerinde başarı kazanmış olanlara bakınız. Bu insanların kronometre gibi hareket ettiklerini görürsünüz. Her şeyi\nzamanında yapacağınıza dair kendi kendinize söz veriniz. Sonra da verilen sözü tutmanın bir namus borcu olduğunu\nhatırınızdan çıkarmayınız. Sözünü tutanlara “karakterli insan” derler. Karakter sahibi olunuz."],"answer":"A","solution":"Doğru cevap A seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Dil ve anlatım","difficulty":"Orta","outcome":"Dil ve anlatım","text":"Şairin, şiiri topluma sevdirmek gibi bir ödevi var mıdır? Bence yoktur hatta böyle bir düşünce çok saçmadır. Şair bir\nduyarlık yakalıyor ve istiyor ki başkaları da o duyarlığı paylaşsın onunla ama paylaşılamaması şairin kabahati değildir. Sanattan çok şey bekliyoruz. Oysa sanatın böyle kaygıları yoktur. Biz şairler, düşünceyle yazmıyoruz; sözcüklerle\nyazıyoruz. Sözcükleri de kullanırken, sözcüklerin gölgelerini kullanıyoruz… Yani imgeyi. Düşünce şiiri diye bir şeyi kavrayamam. O zaman düzyazı yazılsın derim.","stem":"Bu metnin anlatımıyla ilgili,\nI. Soru sorularak okuyucunun dikkati çekilmeye çalışılmıştır.\nII. Tartışmacı bir anlatımdan yararlanılmıştır.\nIII. Geçiş ve bağlantı ifadelerine yer verilmiştir.\nyargılarından hangileri söylenebilir?","options":["Yalnız I","I ve III","II ve III","I, II ve III"],"answer":"D","solution":"Doğru cevap D seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Yardımcı düşünce","difficulty":"Orta","outcome":"Yardımcı düşünce","text":"Dostluk, insanların yakınlık duygusuyla birbirine bağlanmasıdır. Çıkar çok kez kendine dost süsü veren ve durum gerektirdiği için saygı, ilgi gösteren insanlardan bile elde edilebilir. Oysaki dostlukta her şey içten ve doğal olmalıdır. Dostluk,\nkısa süren bir sağanak değil yıllarca akan bir ırmak olmalıdır.","stem":"Bu parçanın dil ve anlatımıyla ilgili aşağıdakilerden hangisi söylenemez?","options":["Deyimlere yer verilmiştir.","İkileme kullanılmıştır.","Benzetmeyle anlatım somutlaştırılmıştır.","Karşılaştırmadan yararlanılmıştır."],"answer":"B","solution":"Doğru cevap B seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Yardımcı düşünce","difficulty":"Orta","outcome":"Yardımcı düşünce","text":"","stem":"Artık Akdeniz sahillerinden uzaktayım. Tepelerinde köyleri, düzlüklerinde tarla ve şehirleriyle örtülü güzel Akdeniz bize\nuzaktan el sallıyor. Buz mavisi rengindeki açık deniz, bize buraların ne kadar kıymetli ve güzel olduğunu öğretti. Anladık\nonun değerini.\nBu parçayla ilgili aşağıdakilerden hangisi söylenemez?","options":["Betimlemeden yararlanılmıştır.","Kişileştirmeye başvurulmuştur.","Söyleşiden alınmıştır.","Kısa cümleler kullanılmıştır."],"answer":"C","solution":"Doğru cevap C seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"Tuzun eski çağlardan bu yana insan yaşamında önemli bir yeri vardır. Öyle ki tuz, bazı uygarlıklar tarafından\n“beyaz altın” olarak adlandırılmıştır. Bazı toplumlar, yerleşim yerlerini tuz kaynaklarının bulunduğu yerlere\ngöre seçmişler, hatta tuzu para yerine kullanmışlardır.\nO eski kitapların muhteşem kokularından uzaklaşıp gözlerimi çini kaplı duvarlara diktim. Kubbenin geleneksel süslemelerine uzun uzun baktım. Kubbenin ortasındaki billur avize aşağı doğru tüm heybetiyle iniyordu.\nBir anıt gibi duran bu avizeye yaklaştım.","stem":"Bu metinlerin ortak yönü aşağıdakilerden hangisidir?","options":["Karşılaştırmadan yararlanılması","Benzetme yapılması","Açıklayıcı anlatımın kullanılması","İkileme kullanılması"],"answer":"B","solution":"Doğru cevap B seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"","stem":"Zalimin elini yakan ateştir\nTüm iyilere doğan güneştir\nDünya halkına gerçek kardeştir\nHer lisan bile dildir hoşgörü\nGelin tanış olalım\nİşi kolay kılalım\nSevelim, sevilelim\nDünya kimseye kalmaz\nBu dizelerin ortak olan yönü aşağıdakilerden hangisidir?","options":["Abartmaya yer verilmesi","Zıtlıklardan yararlanılması","Dize sonlarında ses uyumu olması","Hoşgörüyü konu edinmesi"],"answer":"C","solution":"Doğru cevap C seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"I. Metin\nAğustos böceği, yazın upuzun günleri boyunca gezer,\nsaz çalıp türküler okurmuş. Kış için hiçbir hazırlık yapmaz, elini bir işe bile sürmezmiş. Karıncaysa kafasını\nkullanır, hiç durmadan çalışırmış. Karınca bütün yaz\nkara kış için hazırlık yapar, zamanını boşa harcamazmış.\nII. Metin\nAğustos böceği sanatçıdır. Şarkısını söylemek için\nsoluk tüketip yüreğini parça parça, ışıklı damlalar gibi\nses biçimine sokarak havalara dağıtır. Yorulur, didinir.\nO, başkaları için türkü söylemeye öyle alışmıştır ki\nkendini düşünmez. Bütün bir yaz, kendi özel yaşamını\nbir kerecik olsun aklına getirmez.","stem":"Bu metinlerle ilgili aşağıdaki yargılardan hangisi\nyanlıştır?","options":["Ağustos böceği iki metinde farklı bakış açılarıyla ele\nalınmıştır.","II metinde de öznel ifadelere yer verilmiştir.","I. metinde ağustos böceği olağan, II. metinde ise\nolağanüstü varlık olarak anlatılmıştır.","I. metnin odağında karınca, ikinci metnin odağında\nağustos böceği vardır."],"answer":"C","solution":"Doğru cevap C seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"Mutluluğu aradığın sürece\nMutlu olacak kadar olgun değilsindir\nVe ulaşacak kadar her istediğine\nKayıplara yakındığın sürece\nVe hedeflerin varsa durmadan yöneldiğin\nBilemezsin huzur nedir diye\nMutluluk; bir kuş gibi, kelebek gibi uçarıdır. Onu ne\nkadar kovalarsanız sizden o kadar kaçar. Ama bir\ngün irade gösterip de yüzünüzü başka yöne dönerseniz sessizce gelip omzunuza konuverir. İşte o\nzaman alırsınız onu avcunuzun içine.","stem":"Bu metinlerin mutlulukla ilgili ortak vurgusu aşağıdakilerden hangisidir?","options":["Doğadaki varlıklara benzediği","Umulmayan bir anda insanı bulduğu","Olmadığı yerde huzurun da kalmadığı","Aramakla elde edilemeyeceği"],"answer":"D","solution":"Doğru cevap D seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"Japonya’nın Tokyo kentinde bulunan Tsukiji Pazarı 1935 yılında açılmış. Bu pazarın iç kısmında toptan balık\nsatışı yapan yaklaşık 900 dükkân bulunuyor ve buradaki balıklar genellikle açık artırma yoluyla değişik ülkelerden\ngelen insanlara satılıyor. Pazarın iç kısmı çoğunlukla sabahları açık ve hareketli oluyor. Bu pazarda ton balığı, kılıç\nbalığı, sardalya, deniz yosunu, havyar, balina, yengeç, karides, deniztarağı gibi pek çok deniz ürünü satılıyor.\nBirleşik Krallık’ın başkenti olan Londra’da bulunan Borough Pazarı, Londra’nın en eski pazarı ve yaklaşık bin\nyıldır hizmet veriyor. Pazarda taze sebze ve meyve, peynir, et, balık, hamur işleri gibi çeşitli yiyecekler sabahın\nerken saatlerinde yoğun bir şekilde alıcı buluyor. Farklı ülkelerden satıcılar yerel ürünlerini burada satabiliyorlar.\nÜst katındaki gösteri mutfağında şefler ve aşçılar yemek gösterileri yapıyor, yemek kitabı yazarları pazarda turlar\ndüzenliyor.","stem":"Aşağıdakilerin hangisi bu metinlerde tanıtılan pazarların ortak özelliklerinden biri değildir?","options":["Uzun zamandır kullanılmaları","Deniz canlıları dışında ürünlerin de satılması","İşlek oldukları ortak bir dönemin olması","Farklı kültürlerden insanları bir araya getirmeleri"],"answer":"B","solution":"Doğru cevap B seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"","stem":"Modern insandan yaklaşık bir milyar yıl önce yeşil\nyosunlardan türeyen bitkiler, Dünya’nın tüm evrelerinde evrimleşerek ve bulundukları ortama uyum\nsağlayarak kendilerini korudular. Tabii ki bu süreç\ngerisinde sayılamayacak kadar çok bitki çeşidi bıraktı. Değişen koşullara uyum sağlayabilen bitki\ntürleri ise varlığını sürdürerek doğanın bir parçası\noldu.\nEvlerinin en büyüğü olan yaşlı bir teyzeden bir hatırasını dinlerken bana “Bizim dönemlerde evlenecek\ngelin adayları kuaföre gidemezdi. Babalar buna izin\nvermezdi. Benim babam da doğal olarak bana izin\nvermemişti ama sonra babamın benden yaşça küçük kız kardeşime bu konuda karışmadığı görünce\ndayanamayıp nedenini sordum. O da bana yaşanılan döneme göre davranmak gerektiğini ve şartların\ndeğiştiğini söyledi.”\nBu metinlerde anlatılan durumlardan çıkarılacak\nortak sonuç aşağıdakilerden hangisidir?","options":["Var olan her şey kendi geleceği için içinde bulunulan döneme uyum sağlar.","Eski insanlar çocuklarına karşı daha sert bir şekilde\ndavranmıştır.","Bitkilerin bazıları yok olmasaydı günümüzde insan\nda olmazdı.","Zamana uyum sağlamayan hiçbir şey gelecekte var\nolmayacaktır."],"answer":"A","solution":"Doğru cevap A seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"I. Metin\nAmfibi evler, su içinde yüzebilen veya sular çekilince bağlantısı olan kıyıya oturan evlerdir. Bu evler, sular yükseldiğinde\niçlerinden geçen direkler boyunca yukarı doğru hareket edip alt kısımlarında bulunan dubalar üzerinde yüzmeye başlar.\nKüresel ısınma nedenli deniz yükselmesine karşı çare olarak görülen bu evler; sel, taşkın, kasırga, gelgit nedenli su\ntaşkınlarının görüldüğü yerlerde yaygın kullanılır. Kıyılarda betonlaşmaya iyi bir alternatif olan bu evler ayrıca topraksız\nköylüler için ikamet imkânı sağlamaktadır. ABD, Hollanda, İngiltere, Kanada ve Filipinler’de yaygındır.\nII. Metin\nGezen ev; su üzerinde yatay yer değiştirebilen, karasal bağlantısı bulunmayan, yeri değiştirilebilir evlerdir. Balıkçılıkta ve\nturizmde yaygın kullanılır. Yüzen evlerin en ilkelinden en modernine ev şeklini, konforu ve yapı malzemesini belirleyen\nasıl etken refah seviyesi, bölgesel ihtiyaçlar ve yerel niteliklerdir. Bambu dalları, ahşap, metal, plastik ve betonarme\nyüzen evlerin yapımında kullanılmaktadır. Kanada ve Hollanda konforlu ve donanımlı gezen evlerin en çok kullanıldığı\nülkelerdendir.","stem":"Metinlerde bahsedilen yüzen evlerin,\nI. Kullanılan yapı malzemeleri\nII. Kullanım amaçları\nIII. Yaygın olduğu ülkeler\nözelliklerinden hangileri ortak değildir?","options":["Yalnız I","I ve II","I ve III","II ve III"],"answer":"B","solution":"Doğru cevap B seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"I. Metin\nOrhan Veli Kanık (13 Nisan 1914-14 Kasım 1950), daha çok Orhan Veli olarak tanınan Türk şairdir. Melih\nCevdet ve Oktay Rifat ile birlikte yenilikçi Garip akımının kurucusudur. Türk şiirindeki eski yapıyı temelinden\ndeğiştirmeyi amaçlayarak sokaktaki adamın söyleyişini şiir diline taşımıştır. Şair otuz altı yıllık yaşamına\nşiirlerinin yanı sıra hikâye, deneme, makale ve çeviri\nalanında birçok eser sığdırmıştır.\nII. Metin\nSait Faik Abasıyanık (18 Kasım 1906-11 Mayıs 1954),\nTürk hikâye ve roman yazarı, şairidir. Türk hikâyeciliğinin önde gelen yazarlarından birisi olan Sait Faik,\nçağdaş hikâyeciliğe yaptığı katkılar nedeniyle Türk\nedebiyatının köşe taşlarından biri olarak kabul edilir.\nKlasik öykü tekniğini yıkarak doğayı ve insanları basit,\nsamimi, iyi ve kötü taraflarıyla, olduğu gibi ama aynı\nzamanda şiirsel ve usta bir dille anlattı.","stem":"Aşağıdakilerden hangisi bu metinlerde anlatılan\nyazarların ortak özelliklerinden biridir?","options":["Aynı dönemlerde tanınmış olmaları","Türk hikâyeciliğine yeni bir soluk getirmeleri","Kitap yazmaya aynı yıllarda başlamaları","Aynı türden eserler vermeleri"],"answer":"D","solution":"Doğru cevap D seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"I. Metin\nMars, Güneş sisteminin Güneş’ten itibaren dördüncü\ngezegenidir. Adını Roma mitolojisindeki savaş tanrısı\nMars’tan almıştır. Yüzeyindeki yaygın demir oksitten\ndolayı kızılımsı bir görünüme sahip olduğu için “Kızıl\nGezegen” de denir.\nİnce bir atmosferi olan Mars gerek Ay’daki gibi meteor\nkraterlerini, Dünya’daki gibi volkan, vadi, çöl ve kutup\nbölgelerini içeren çehresiyle silikat kayalardan oluşan\nbir gezegendir.\nII. Metin\nMars’a gönderilen araçlar içinde en gelişmiş teknolojik özelliklere sahip olmasıyla bilinen Perseverance,\nKızıl Gezegen’in atmosferinden aldığı karbondioksiti\noksijene çevirmeyi başardı. Oksijen üretimi, Perseverance’ın sağ kısmında yer alan ve MOXIE adı verilen\ncihaz tarafından gerçekleştirildi. MOXIE, ilk çalışmasında 5 gram oksijen üretmeyi başardı. Bunun, rutin\nfaaliyette bulunan bir astronotun 10 dakika nefes almasını sağlayabilecek bir miktar olduğu belirtildi.","stem":"Bu metinlerin ortak olan yönü aşağıdakilerden\nhangisidir?","options":["Tanımlamaya başvurulması","Kanıtlanabilir ifadelerin bulunması","Benzetme yapılması","Sayısal verilerden yararlanılması"],"answer":"B","solution":"Doğru cevap B seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"","stem":"Ormanlık alanlarda, parklarda\nve bahçelerde görülür.\nBöceklerle, tohumlarla\nve meyvelerle beslenir.\nKuyruk, kanat ve başın üstü mavi, alın ve\nyanaklar beyaz, sırtı yeşil, karnı ise tümüyle\nsarıdır.\nCivcivleri 12-16 günde yumurtadan çıkar.\nOrmanlık alanlarda, dere\nboylarında ve bahçelerde görülür.\nBöceklerle ve meyvelerle\nbeslenir.\nÜst tüyleri sırtta kızıla çalan düz, sıcak bir\nkahverengidir, alt tüyleri kır olur, boğazı daha\nsoluk renktedir.\nCivcivleri 13-14 günde yumurtadan çıkar.\nBÜYÜK BAŞTANKARA BÜLBÜL\n14-20 mm 14 cm 23-26 cm 14-22 g 15-21 mm 16-17 cm 23-26 cm 18-27 g\nBu metinlerde tanıtılan kuşlar,\nI. Renkleri\nII. Kuluçka süreleri\nIII. Boyutları\nIV. Yaşam alanları\nV. Besin kaynakları\nözelliklerinin hangileri bakımından benzer değildir?","options":["Yalnız I","I ve II","I, III ve IV","IV ve V"],"answer":"A","solution":"Doğru cevap A seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"","stem":"I. Metin\nHer yazıda mutlaka yazarın yaşantısının izleri bulunur.\nBir romanda veya hikâyede olayın geçtiği yer, kahramanlardan biri veya birkaçı, anlatılan dönem yazarın\nhayatı ile örtüşür. Ancak hiçbir yazar kendi hayatını\neserine yansıtmak istemez. Çünkü bu, yazın ve anlatı\niçin başarısızlık olarak görülür.\nII. Metin\nLafı eğip bükmeye hiç gerek yok. En çok okunan\nromanımda dedemi anlatmıştım. Ne bir eksik ne bir\nfazla. Biliyorum, diyeceksiniz ki o zaman buna roman\ndenir mi? Evet, denir ve dendi. Çok başarılı da oldu.\nBu yüzden diyorum ki mesele romanın kurgusal olup\nolmaması değil, anlatımının sürükleyici olmasıdır.\nBu metinler,\nI. Ele alınan konu\nII. Dilin sadeliği\nIII. Bakış açısı\nIV. Kullanılan üslup\nözelliklerinin hangileri bakımından ortak değildir?","options":["I ve II","I ve III","II ve IV","III ve IV"],"answer":"D","solution":"Doğru cevap D seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"I. Metin\nUzaktan eğitim, yüz yüze eğitimin aksine mesafeleri\nortadan kaldırır. İstediğiniz zaman, istediğiniz yerde\nulaşabileceğiniz bilgiler veya dersler genellikle kısa\nparçalar hâlinde servis edilir. Bu sayede diğer işlerinizin arasında kalan vakitleri bile değerlendirebilirsiniz.\nII. Metin\nUzaktan eğitimle çocuklarda özellikle bilişsel dikkat,\nalgı ve öğrenmelerinde sorunlar yaşanmaya başlandı.\nGerçek ortam yerine sürekli bilgisayar başında zaman\ngeçiren çocukların büyük kas motor becerileri yani\nkoşma, ayakta durma, yürüme gibi becerilerinde; küçük kas motor gelişimi olan yazma, kavrama, çizme,\nyapıştırma gibi becerileri olumsuz etkilendiği bilinmektedir.","stem":"Aşağıdakilerden hangisi bu metinlerin ortak yönlerinden biri değildir?","options":["Karşılaştırma yapılması","Aynı konuya farklı açılardan bakılması","Açıklayıcı anlatıma başvurulması","Tanımlamadan yararlanılması"],"answer":"D","solution":"Doğru cevap D seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"Bir konunun sohbet havasında, doğal bir dille anlatıldığı, düşüncelerin derinleştirilmeden yüzeysel olarak aktarıldığı\nyazılara söyleşi (sohbet) denir.","stem":"Buna göre aşağıdakilerden hangisi bir sohbetten alınmış olamaz?","options":["Küçükken fablların vazgeçilmez kahramanı ormanlar kralı aslanı dinlemek bile yüreklerimize korku salardı. Ancak\nhayvanat bahçelerinde gördüğüm aslanların hayallerimdekilerden farklı. Siz de benim düşündüğüm gibi mi düşünüyorsunuz? Yerinden kıpırdamayan, yemeği bakıcıları tarafından önüne getirilen aslanın krallığı sona ermemiş midir?\nGerçekten de ne üzücü!","İleri bir toplum seviyesine ulaşmak çoğumuzun hayallerini süslüyor. Peki, gelişmiş Batı medeniyetleri seviyesine\nyükselmek sadece Batılı gibi yaşamaktan mı ibarettir? Yani Batılılar gibi giyinip onlar gibi yaşarsak biz de gelişmiş\nbir toplum olabilir miyiz? Bence en güzeli bize düşen sorumlulukların farkında olup toplumumuzu refah düzeye ulaştırmada üzerimize düşeni yapmaktır.","Balkonumuzun köşesinden çiçeklerinin güzel kokusunu duyduğum akasya ağacın gölgesinde oturup kitap okumak\nbenim huzur kaynağımdır. Bu güzel ağacı dedem ben doğduğumda dikmiş, o büyümüş, ben büyümüşüm. Küçükken akasyaya tırmanıp güzel çiçeklerinden toplar, anneme hediye ederdim. Bence anneminkinden sonra en güzel\nkoku akasyanınkiydi.","Sevgi neydi sahi, neleri ya da kimleri gözü kapalı sevebilirdik? Herhâlde çoğunuz ilk olarak anne ve babasını söyler.\nÇünkü ilk onları sever, ilk onlara bağlanırız. Daha sonra etrafımızı keşfettikçe sevgi dağarcığımızda genişler. Daha\nçok sevmeye başlarız. Oyuncak bebeğimizi, kurşun askerlerimizi, atımızı, bizi sevenleri…"],"answer":"C","solution":"Doğru cevap C seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Paragrafta anlam","difficulty":"Orta","outcome":"Paragrafta anlam","text":"Bilirsiniz, meşhur hikâyedir: Nasrettin Hoca’ya ahbapları, “Eskimiş Ayları ne yaparlar?” diye sormuşlar, o da “Kırpar,\nyıldız yaparlar.” demiş. Bu cevap ilk bakışta pek saçma gibi görünür. Ama biraz düşünürseniz Hoca’nın ne demek istediğini anlarsınız. O; Ay’ın tam 30 gün gökte türlü şekillerde görüldüğünü, sonra giderken gökteki yıldızlar gibi parça\nparça ışıldayan hatıralar hâline geldiğini ve onu bir bütün olarak görmenin bir daha mümkün olmayacağını bu sözüyle\nne güzel anlatmıştır. İçimizden hangimiz hayatımızda geçmiş olan yüzlerce ayı bir bütün olarak hatırlayabilir, dakikalarıyla yeniden yaşayabilir? Bilmem siz de aynı fikirde misiniz? Bana öyle geliyor ki Hoca, eskimiş Ayların kırpılıp yıldız\nyapıldığını söylerken bunu kestirmiştir.","stem":"Bu metnin yazıldığı türle ilgili aşağıdakilerden hangisi doğrudur?","options":["Bir kişinin başından geçen olaylar aktarılmıştır.","Toplumu derinden etkileyen olağanüstü olaylar hikâye edilmiştir.","Düşünceler, okuyucunun karşısındaymış gibi samimi bir üslupla ifade edilmiştir.","Bir konuyla ilgili tespitler bilimsel gerçekliğe uygun olarak anlatılmıştır."],"answer":"C","solution":"Doğru cevap C seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Metin türleri","difficulty":"Orta","outcome":"Metin türleri","text":"1964-1968 yıllarım Ankara ve İzmir’de geçti. Gazi Eğitim Enstitüsü (Üniversitesi) Resim Bölümünden mezun\noldum. Gerçek bilgiyi öğrendim. Sanatı, felsefeyi,\noperayı, tiyatro ve diğer etkinlikleri bol bol soludum.\nAnkara’da çok değerli hocalarım ve sınıf arkadaşlarımla hayatı, dostluğu, çalışmayı, başarmayı öğrendim.\n1968 yılında ilk sergimi İzmir’de açtım. Özel bir kolejde\nresim, sanat tarihi öğretmenliği yaptım.","stem":"Bu parça aşağıdaki metin türlerinin hangisinden\nalınmıştır?","options":["Otobiyografi","Söyleşi","Günlük","Biyografi"],"answer":"A","solution":"Doğru cevap A seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Metin türleri","difficulty":"Orta","outcome":"Metin türleri","text":"22 Haziran\nSabah 06.00'da uyandım. Daha doğrusu uyandırıldım. Çilek toplama işi erken saatte yapılırmış. Carol, bana kendi\ngiysilerinden eski bir kot, kirli bir ayakkabı, kalın çoraplar ve gömlek verdi. Çamurlara batacakmışız da… Carol'ın\n39 numara ayakkabılarını, ayağıma oturması için üç çift çorapla giydim. Eski kotu ve gömleği de üzerime çekince\nhazır olduğumu sanıyordum. Değilmişim! Üzerimize sivrisinek koruyucu sprey sıkmadan çıplak sayılırmışız. Yeşillik\nçok olduğundan, yapılan ilaçlamalar yetersiz kalıyormuş.","stem":"Bu metnin türü aşağıdakilerden hangisi olabilir?","options":["Mektup","Söyleşi","Günlük","Haber yazısı"],"answer":"C","solution":"Doğru cevap C seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Metin türleri","difficulty":"Orta","outcome":"Metin türleri","text":"Gönen Köy Enstitüsünde öğrenciyken fotoğraf çekme meraklısıydım. Filmlerin banyosunu Afyon’da yaptırıyordum.\nFotoğraflar en az bir haftada geliyordu. Bir keresinde on günü geçti, fotoğraflar gelmedi. Bir kamyona atlayıp Afyon’a\ngittim. Fotoğrafçı bir bavuldan yüzlerce film, içerisi resim dolu yüzlerce zarf çıkardı. Sıra ile okumaya başladı. Tahir, Mahir, Zahir, Bekir, Tekir, Fakır, Çakır, Makir, Fakir... Uyaklı sözcükler içinde Fakir ilgimi çekmişti. Tam o sırada düşündüm,\nşu kararı verdim. Bundan sonra şiir, öykü ve romanlarımı Tahir Baykurt değil, Fakir Baykurt adı ile yazacaktım.","stem":"Bu parça aşağıdaki metin türlerinin hangisinden alınmıştır?","options":["Biyografi","Anı","Deneme","Gezi yazısı"],"answer":"B","solution":"Doğru cevap B seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Metin türleri","difficulty":"Orta","outcome":"Metin türleri","text":"06 Ekim 1985’te Hatay’da dünyaya geldim. Babamın adı Aslan, annemin adı Birgül’dür. Babam ve annem aynı üniversitede, tıp fakültesinde tanışmışlar. Ailem uzun süre doktorluk yaptıktan sonra ben edebiyat bölümünü kazanıp\nüniversiteye başlayınca emekli oldular. Ben şu an Gazi Üniversitesinde öğretim görevlisi olarak çalışmaktayım. İşimi\nseverek yapmamın yanı sıra akademik çalışmalarla kendimi devamlı geliştiriyorum.","stem":"Bu metnin türü aşağıdakilerin hangisinde tanımlanmıştır?","options":["Bir kişinin kendi yaşam öyküsünü anlattığı yazı ya da eserdir.","Ünlü bir kişinin hayatının onu tanıyan biri tarafından anlatıldığı yazılardır.","Bir kişinin başından geçenleri günü gününe kaleme aldığı yazı türüdür.","Bir kişinin bir konu hakkındaki düşüncelerini doğal bir dille anlattığı yazılardır."],"answer":"A","solution":"Doğru cevap A seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true},{"grade":7,"topic":"Metin türleri","difficulty":"Orta","outcome":"Metin türleri","text":"Türk tekno müzik sanatçısı Arkın Ilıcalı, 1966 yılında Bursa’da dünyaya geldi. Sanatçı, “Mercan Dede” ismini, İhsan\nOktay Anar’ın romanındaki “Mercan Dede” karakterinden esinlenerek almıştır. Müzik eğitimini geleneksel yollardan tasavvuf müzik ustalarından aldı. Ayrıca sanatçı, ebru sanatını öğrendiği büyük ney üstadı Niyazi Sayın’dan da fazlasıyla\netkilendi. Ebru sanatını eğitmen olarak Concordia Üniversitesinin Studio Arts programında devam ettiren Mercan Dede,\n1997 yılında Kanada’ya göç etti. Burada güzel sanatlar üzerine lisans ve yüksek lisans eğitimini tamamlayan Mercan\nDede; aynı üniversitede başladığı öğretim üyeliğine, müzik çalışmalarının ağırlık kazanması sebebiyle kısa bir süre önce\nara verdi.","stem":"Bu metnin türüyle ilgili aşağıdakilerden hangisi yanlıştır?","options":["Ünlü bir kişinin hayatı başkası tarafından anlatılmıştır.","Ele alınan kişi belirgin özellikleriyle verilmiştir.","Olaylar ve bilgiler oluş sırasına göre yazılmıştır.","Anlatım içinde kişisel görüşler ön plana çıkmıştır."],"answer":"D","solution":"Doğru cevap D seçeneğidir.","wrong":"Metindeki kanıtları ve soru kökündeki anahtar ifadeyi yeniden karşılaştırınız.","strategy":"Önce soru kökünü okuyup ardından metindeki ilgili kanıtları seçeneklerle karşılaştırınız.","hint":"Soru kökündeki sınırlayıcı ifadeye dikkat ediniz.","keepOptionOrder":true,"plainText":true}];
